        /// <summary>
        /// Initializes a new instance of the <see cref="T:Gizmox.WebGUI.Forms.DataGridView"></see> class.
        /// </summary>
        public DataGridView()
        {
            this.menmEditMode = DataGridViewEditMode.EditOnKeystrokeOrF2;
            this.menmRowHeadersWidthSizeMode = DataGridViewRowHeadersWidthSizeMode.EnableResizing;
            this.mobjCurrentCellPoint = new Point(-1, -1);
            this.mintRowHeadersWidth = 0x29;
            this.mintColumnHeadersHeight = 0x17;
            this.menmColumnHeadersHeightSizeMode = DataGridViewColumnHeadersHeightSizeMode.EnableResizing;
            this.mobjAdvancedDataGridViewBorderStyle = new DataGridViewAdvancedBorderStyle(this);
            this.NewRowIndex = -1;
            this.mobjDataGridViewState1[0x80001b] = true;
            this.mobjDataGridViewState1[0x80] = true;
            this.mobjDataGridViewState2[0x60003e7] = true;
            this.DisplayedBandsInfo = new DisplayedBandsData();
            this.ColumnHeadersVisible = true;
            this.mobjBackgroundColor = DefaultBackgroundBrush.Color;
            this.DimensionChangeCount = 0;
            this.SelectedBandIndexes = new DataGridViewIntLinkedList();
            this.IndividualSelectedCells = new DataGridViewCellLinkedList();
            this.IndividualReadOnlyCells = new DataGridViewCellLinkedList();
            this.menmSelectionMode = DataGridViewSelectionMode.RowHeaderSelect;
            this.menmExpansionIndicator = ShowExpansionIndicator.CheckOnExpand;
            this.SortOrder = SortOrder.None;
            this.menmScrollBars = ScrollBars.Both;
            this.menmClipboardCopyMode = DataGridViewClipboardCopyMode.EnableWithAutoHeaderText;
            this.HierarchyLevel = -1;

            base.SetStyle(ControlStyles.UserMouse | ControlStyles.Opaque | ControlStyles.UserPaint, true);
            base.SetStyle(ControlStyles.SupportsTransparentBackColor, false);

            LayoutData objLayoutData = new LayoutData();
            objLayoutData.TopLeftHeader = Rectangle.Empty;
            objLayoutData.ColumnHeaders = Rectangle.Empty;
            objLayoutData.RowHeaders = Rectangle.Empty;
            objLayoutData.ColumnHeadersVisible = true;
            objLayoutData.RowHeadersVisible = true;
            this.LayoutInfo = objLayoutData;

            this.BorderStyle = BorderStyle.FixedSingle;
            this.menmAutoSizeRowsMode = DataGridViewAutoSizeRowsMode.None;
            this.menmAutoSizeColumnsMode = DataGridViewAutoSizeColumnsMode.None;

            // Initialize the grouping style properties.
            InitializeGroupingStyleProperties();

        }

        /// <summary>
        /// Initializes the grouping style properties.
        /// </summary>
        private void InitializeGroupingStyleProperties()
        {
            DataGridViewSkin objSkin = SkinFactory.GetSkin(this) as DataGridViewSkin;
            if (objSkin != null)
            {
                mobjGroupingAreaBackColor = objSkin.GroupingDropAreaStyle.BackColor;
                mobjGroupingAreaBorderColor = objSkin.GroupingDropAreaStyle.BorderColor;
                mobjGroupingAreaBorderStyle = objSkin.GroupingDropAreaStyle.BorderStyle;
                mobjGroupingAreaBorderWidth = objSkin.GroupingDropAreaStyle.BorderWidth;
                menmGroupingAreaBackgroundImageRepeat = objSkin.BackgroundImageRepeat;
                menmGroupingAreaBackgroundImagePosition = objSkin.BackgroundImagePosition;
                mintGroupingAreaHeight = objSkin.DropAreaHeight;
            }
        }

