        #region Methods

        #region Events Related

        /// <summary>
        /// 
        /// </summary>
        /// <returns></returns>
        protected override CriticalEventsData GetCriticalEventsData()
        {
            CriticalEventsData objEvents = base.GetCriticalEventsData();

            if (SelectionChangedHandler != null || CurrentCellChangedHandler != null || this.IsSelectionChangeCritical)
            {
                objEvents.Set(WGEvents.SelectionChange);
            }

            if (this.ColumnDividerDoubleClickHandler != null)
            {
                objEvents.Set(WGEvents.ColumnDividerDoubleClick);
            }

            if (this.RowExpandingHandler != null || this.RowExpandedHandler != null)
            {
                objEvents.Set(WGEvents.Expand);
            }

            if (this.GetHandler(EVENT_ROWCOLLAPSED) != null || this.GetHandler(EVENT_ROWCOLLAPSING) != null)
            {
                objEvents.Set(WGEvents.Collapse);
            }

            return objEvents;
        }

        /// <summary>
        /// Gets the critical client events.
        /// </summary>
        /// <returns></returns>
        protected override CriticalEventsData GetCriticalClientEventsData()
        {
            CriticalEventsData objEvents = base.GetCriticalClientEventsData();
            if (this.HasClientHandler("SelectionChanged"))
            {
                objEvents.Set(WGEvents.SelectionChange);
            }

            if (this.HasClientHandler("DividerDoubleClick"))
            {
                objEvents.Set(WGEvents.ColumnDividerDoubleClick);
            }

            if (this.HasClientHandler("Expand"))
            {
                objEvents.Set(WGEvents.Expand);
            }

            if (this.HasClientHandler("Collapse"))
            {
                objEvents.Set(WGEvents.Collapse);
            }

            if (this.HasClientHandler("BeginEdit"))
            {
                objEvents.Set(WGEvents.BeginEdit);
            }

            if (this.HasClientHandler("EndEdit"))
            {
                objEvents.Set(WGEvents.EndEdit);
            }

            return objEvents;
        }

        /// <summary>
        /// Gets the list of tags that client events are propogated to.
        /// </summary>
        /// <value>
        /// The client event propogated tags.
        /// </value>
        protected override string ClientEventsPropogationTags
        {
            get
            {
                return string.Format("WG:{0},WG:{1},WG:{2}", WGTags.DataGridViewRow, WGTags.DataGridViewColumn, WGTags.DataGridViewCell);
            }
        }

        /// <summary>
        /// Fires an event.
        /// </summary>
        /// <param name="objEvent">event.</param>
        protected override void FireEvent(IEvent objEvent)
        {
            string strMember = objEvent.Member;
            if (objEvent.Type == "VisualTemplate")
            {
                base.FireEvent(objEvent);
            }
            else if (string.IsNullOrEmpty(strMember))
            {
                base.FireEvent(objEvent);

                // Select event type
                switch (objEvent.Type)
                {
                    #region Navigate
                    case "Navigate":
                        string strTo = objEvent["To"];
                        switch (strTo)
                        {
                            case "End":
                                this.CurrentPage = this.TotalPages;
                                break;
                            case "Home":
                                CurrentPage = 1;
                                break;
                            case "Next":
                                if (this.CurrentPage < this.TotalPages)
                                {
                                    this.CurrentPage = this.CurrentPage + 1;
                                }
                                break;
                            case "Back":
                                if (this.CurrentPage > 1)
                                {
                                    this.CurrentPage = this.CurrentPage - 1;
                                }
                                break;
                            default:
                                int intPage;
                                if (int.TryParse(strTo, out intPage) && intPage > 0 && intPage <= this.TotalPages)
                                {
                                    this.CurrentPage = intPage;
                                }
                                
                                break;
                        }

                        // Fires when requested to navigate to a different page.
                        EventHandler objEventHandler = this.PagingChangedHandler;
                        if (objEventHandler != null)
                        {
                            objEventHandler(this, EventArgs.Empty);
                        }
                        break;
                    #endregion

                    #region Delete

                    case "Delete":
                        if (ProcessDeleteKey(Keys.Delete))
                        {
                            // Redraw grid.
                            this.Update();

                            // Sets the focus back to the grid.
                            this.SetFocus();
                        }
                        break;

                    #endregion

                    #region SelectionChanged

                    case "SelectionChanged":

                        // Indicates in selection changing mode
                        this.NoSelectionChangeCount++;
                        bool blnIsIncremental = objEvent["Incremental"] == "1";

                        try
                        {
                            // Get the value attribute.
                            string strValue = objEvent[WGAttributes.Value];

                            // If there is a valid selected value
                            if (strValue != null)
                            {
                                // Check if should select all cells.
                                bool blnSelectAll = (strValue == "*");

                                // Get grid's selection mode.
                                DataGridViewSelectionMode enmDataGridViewSelectionMode = this.SelectionMode;

                                // Get all selected members
                                string[] arrSelectedMembers = strValue.Split(',');

                                // Get working set - this current page if multiselect and ctrl key pressed, otherwise all rows 
                                IList objRangeRows = this.MultiSelect && blnIsIncremental ? this.PageRows : this.Rows;

                                // Loop all page rows or all rows depending on multi selection value
                                foreach (DataGridViewRow objRow in objRangeRows)
                                {
                                    if (objRow.Visible || blnSelectAll)
                                    {
                                        // Handle CellSelect selection mode and  RowHeaderSelect selection mode.
                                        if (enmDataGridViewSelectionMode == DataGridViewSelectionMode.CellSelect || enmDataGridViewSelectionMode == DataGridViewSelectionMode.RowHeaderSelect)
                                        {
                                            // Loop all row's cells.
                                            foreach (DataGridViewCell objCell in objRow.Cells)
                                            {
                                                if (objCell.Selected)
                                                {
                                                    if (!blnSelectAll && !this.HasValue(arrSelectedMembers, objCell.MemberIDInternal))
                                                    {
                                                        objCell.ClientState |= DataGridViewElementClientStates.Selected;
                                                        SetSelectedCellCore(objCell.ColumnIndex, objCell.RowIndex, false, true);
                                                        objCell.ClientState &= ~DataGridViewElementClientStates.Selected;
                                                    }
                                                }
                                                else
                                                {
                                                    if (blnSelectAll || this.HasValue(arrSelectedMembers, objCell.MemberIDInternal))
                                                    {
                                                        objCell.ClientState |= DataGridViewElementClientStates.Selected;
                                                        SetSelectedCellCore(objCell.ColumnIndex, objCell.RowIndex, true, true);
                                                        objCell.ClientState &= ~DataGridViewElementClientStates.Selected;
                                                    }
                                                }
                                            }
                                        }

                                        // Handle FullRowSelect selection mode and  RowHeaderSelect selection mode.
                                        if (enmDataGridViewSelectionMode == DataGridViewSelectionMode.FullRowSelect || enmDataGridViewSelectionMode == DataGridViewSelectionMode.RowHeaderSelect)
                                        {
                                            if (objRow.Selected)
                                            {
                                                if (!blnSelectAll && !this.HasValue(arrSelectedMembers, objRow.MemberIDInternal))
                                                {
                                                    objRow.ClientState |= DataGridViewElementClientStates.Selected;
                                                    SetSelectedRowCore(objRow.Index, false, true);
                                                    objRow.ClientState &= ~DataGridViewElementClientStates.Selected;
                                                }
                                            }
                                            else
                                            {
                                                if (blnSelectAll || this.HasValue(arrSelectedMembers, objRow.MemberIDInternal))
                                                {
                                                    objRow.ClientState |= DataGridViewElementClientStates.Selected;
                                                    SetSelectedRowCore(objRow.Index, true, true);
                                                    objRow.ClientState &= ~DataGridViewElementClientStates.Selected;
                                                }
                                            }
                                        }
                                    }
                                }
                            }

                            // If there is a valid current cell
                            if (objEvent.Contains(WGAttributes.CurrentCell))
                            {
                                // Get member position.
                                Point objMemberPosition = GetMemberPosition(objEvent[WGAttributes.CurrentCell]);

                                // Validate position.
                                // Validate that the row been selected is on the current page.
                                if (!this.IsInnerCellOutOfBounds(objMemberPosition.X, objMemberPosition.Y) &&
                                    this.PageRows.Contains(this.Rows.SharedRow(objMemberPosition.Y)))
                                {
                                    // Check if the current cell changed and do validateCurrentCell if needed
                                    bool blnCurrentCellChange = (this.mobjCurrentCellPoint.Y != objMemberPosition.Y) || (this.mobjCurrentCellPoint.X != objMemberPosition.X);

                                    // Update the proposed current cell's client state.
                                    this[objMemberPosition.X, objMemberPosition.Y].ClientState |= DataGridViewElementClientStates.CurrentCell;

                                    // Set proposed current cell. 
                                    this.SetCurrentCellAddressCore(objMemberPosition.X, objMemberPosition.Y, true, blnCurrentCellChange, false, true);

                                    // Check if the proposed current cell is still in valid bounds (after current cell 
                                    // cahnging that might have triggerd external events).
                                    if (!this.IsInnerCellOutOfBounds(objMemberPosition.X, objMemberPosition.Y))
                                    {
                                        // Update the new current cell's client state.
                                        this[objMemberPosition.X, objMemberPosition.Y].ClientState &= ~DataGridViewElementClientStates.CurrentCell;
                                    }
                                }
                            }
                        }
                        finally
                        {
                            this.NoSelectionChangeCount--;
                        }

                        break;
                    #endregion

                    #region ColumnsReorder

                    case "ColumnsReorder":
                        if (objEvent.Contains(WGAttributes.DraggedColumn) && objEvent.Contains(WGAttributes.TargetColumn))
                        {
                            // Get dragged and target columns indexes.
                            int intDraggedColumnIndex = Convert.ToInt32(objEvent[WGAttributes.DraggedColumn]);
                            int intTargetColumnIndex = Convert.ToInt32(objEvent[WGAttributes.TargetColumn]);

                            // Validate columns indexes.
                            if (intDraggedColumnIndex >= 0 && intDraggedColumnIndex < this.Columns.Count &&
                                intTargetColumnIndex >= 0 && intTargetColumnIndex < this.Columns.Count &&
                                this.Columns[intDraggedColumnIndex] != null && this.Columns[intTargetColumnIndex] != null)
                            {
                                // Get target column display index.
                                int intTargetDisplayIndex = this.Columns[intTargetColumnIndex].DisplayIndex;

                                // In case that dragged column display index is bigger the the target column display index -
                                // increase the target column display index by one.
                                if (this.Columns[intDraggedColumnIndex].DisplayIndex > intTargetDisplayIndex) 
                                {
                                  
                                    if (!(objEvent[WGAttributes.Before] == "1"))
                                    {
                                        // Update dragged column's display index.
                                        intTargetDisplayIndex += 1;
                                    }
                                }

                                // Update dragged column's display index.
                                this.Columns[intDraggedColumnIndex].DisplayIndex = intTargetDisplayIndex;

                                // Perform a sort on the columns collection (as for display index)
                                this.Columns.InvalidateCachedColumnsOrder();

                                // Update the whole grid.
                                this.Update();
                            }
                        }
                        break;

                    #endregion

                    #region ClearFilters

                    // Cancel all filters.
                    case "ClearFilters":
                        ClearAllFilters();
                        break;

                    #endregion

                    #region OpenColumnChooser

                    case "OpenColumnChooser":
                        // Create and show the dialog
                        ShowColumnPickerDialog();
                        break;

                    #endregion

                    #region InsertGroup

                    case "InsertGroup":

                        // Get the dragged (new) group column data property name, and the target (previous) one.
                        // Note: target can be null.
                        string strTargetColumnDataPropertyName = objEvent[WGAttributes.TargetColumn] ?? string.Empty;
                        string strDraggedColumnDataPropertyName = objEvent[WGAttributes.DraggedColumn];

                        // Insert new group into GroupingColumns.
                        if (!string.IsNullOrEmpty(strDraggedColumnDataPropertyName))
                        {
                            InsertGroupingColumn(strTargetColumnDataPropertyName, strDraggedColumnDataPropertyName);

                            // Raise GroupingChanged if needed.
                            this.OnGroupingChanged(DataGridViewGroupingAction.Add, strDraggedColumnDataPropertyName);
                        }
                        break;

                    #endregion


                }
            }
            // If is a datagridview block
            else if (strMember.StartsWith(WGTags.DataGridViewBlock))
            {
                int intBlockId = -1;

                // If there is a valid block id
                if (int.TryParse(strMember.Substring(4), out intBlockId))
                {
                    // If is load event
                    if (objEvent.Type == "Load")
                    {
                        // Get the grid block info
                        DataGridRowBlockInfo objBlockInfo = this.GetBlockInfo(intBlockId);
                        if (objBlockInfo != null)
                        {
                            // Load the block's rows.
                            objBlockInfo.LoadRows();

                            // Update block;
                            objBlockInfo.Update();
                        }
                    }
                }
            }
            else
            {
                // Get member position.
                Point objMemberPosition = GetMemberPosition(strMember);

                if (objMemberPosition.X != -1 && objMemberPosition.Y != -1)
                {
                    // Check member type.
                    char chrMemberType = strMember[0];

                    switch (chrMemberType)
                    {
                        case 'D':
                            DataGridViewRow objDataGridViewRow = Rows.SharedRow(objMemberPosition.Y);
                            if (objDataGridViewRow != null)
                            {
                                // Fire cell's event.
                                objDataGridViewRow.Cells[objMemberPosition.X].FireEvent(objEvent);
                            }
                            break;
                        case 'C':
                            this.Columns[objMemberPosition.X].FireEvent(objEvent);
                            break;
                        case 'R':
                            DataGridViewRow objHandledDataGridViewRow = null;

                            if (this.ShowFilterRow)
                            {
                                if (objMemberPosition.Y == 0)
                                {
                                    objHandledDataGridViewRow = this.mobjDataGridViewFilterRow;
                                }
                                else
                                {
                                    objHandledDataGridViewRow = this.Rows.SharedRow(objMemberPosition.Y - 1);
                                }
                            }
                            else
                            {
                                objHandledDataGridViewRow = this.Rows.SharedRow(objMemberPosition.Y);
                            }

                            if (objHandledDataGridViewRow != null)
                            {
                                // Fire row's event.
                                objHandledDataGridViewRow.FireEvent(objEvent);
                            }
                            break;
                    }
                }
                else
                {
                    //if we have an x value this is a column
                    if (objMemberPosition.X != -1)
                    {
                        //Get the column
                        DataGridViewHeaderCell objDataGridViewHeaderCell = this.Columns[objMemberPosition.X].HeaderCell;
                        if (objDataGridViewHeaderCell != null)
                        {
                            //Raise column fire event
                            objDataGridViewHeaderCell.FireEvent(objEvent);
                        }
                    }
                    //if we have an y value this is a row
                    else if (objMemberPosition.Y != -1)
                    {
                        //Get the Row
                        DataGridViewHeaderCell objDataGridViewHeaderCell = this.Rows[objMemberPosition.Y].HeaderCell;
                        if (objDataGridViewHeaderCell != null)
                        {
                            //Rasie the fire event
                            objDataGridViewHeaderCell.FireEvent(objEvent);
                        }
                    }
                    //if it is the TopLeftHeaderCell
                    else if (strMember == this.TopLeftHeaderCell.MemberIDInternal)
                    {
                        this.TopLeftHeaderCell.FireEvent(objEvent);
                    }
                }
            }
        }

        /// <summary>
        /// Called when [grouping changed].
        /// </summary>
        /// <param name="strColumnDataPropertyName">Name of the STR dragged column data property.</param>
        internal void OnGroupingChanged(DataGridViewGroupingAction enmAction, string strColumnDataPropertyName)
        {
            // if valid data property name provided
            if (!string.IsNullOrEmpty(strColumnDataPropertyName))
            {
                DataGridViewColumnCollection arrColumns = this.Columns;

                string strColumnName = arrColumns.GetRealDataMemberForProposedMember(strColumnDataPropertyName);

                DataGridViewColumn objColumn = arrColumns[strColumnName];

                // If such column exists
                if (objColumn != null)
                {
                    // If registered, raise handler.
                    if (this.GroupingChangedEventHandler != null)
                    {
                        // Create GroupingChangedEventArgs
                        GroupingChangedEventArgs objArgs = new GroupingChangedEventArgs(enmAction, objColumn);

                        // Call handler.
                        GroupingChangedEventHandler(this, objArgs);
                    }
                }
            }
        }

        /// <summary>
        /// Clears all filters.
        /// </summary>
        public void ClearAllFilters()
        {
            mblnSuspendFilterInitialization = true;

            try
            {
                // Check if  ShowFilterRow exist
                if (this.ShowFilterRow && this.mobjDataGridViewFilterRow != null)
                {
                    // Loop on all FilterCell and clear theirs filter
                    foreach (DataGridViewFilterCell objDataGridViewFilterCell in this.mobjDataGridViewFilterRow.Cells)
                    {
                        objDataGridViewFilterCell.ClearFilter(true);
                    }
                }
                else
                {
                    // Clear columns filters
                    foreach (DataGridViewColumn objColumn in this.Columns)
                    {
                        objColumn.ClearFilter(true);
                    }
                }
            }
            finally
            {
                mblnSuspendFilterInitialization = false;
            }

            // Applay new filter(no filter)
            this.ApplyDataGridViewFilter();
        }

        /// <summary>
        /// Sets the focus abck to the grid.
        /// </summary>
        private void SetFocus()
        {
            // Get application context.
            IApplicationContext objApplicationContext = this.Context as IApplicationContext;
            if (objApplicationContext != null)
            {
                // Set focus.
                objApplicationContext.SetFocused(this, true);
            }
        }

        /// <summary>
        /// Sets the selected cell core.
        /// </summary>
        /// <param name="intColumnIndex">Index of the int column.</param>
        /// <param name="intRowIndex">Index of the int row.</param>
        /// <param name="blnSelected">if set to <c>true</c> [BLN selected].</param>
        /// <param name="blnClientSource">if set to <c>true</c> [BLN client source].</param>
        private void SetSelectedCellCore(int intColumnIndex, int intRowIndex, bool blnSelected, bool blnClientSource)
        {
            if ((intColumnIndex < 0) || (intColumnIndex >= this.Columns.Count))
            {
                throw new ArgumentOutOfRangeException("columnIndex");
            }

            // Get the Grid Rows
            DataGridViewRowCollection objRows = this.Rows;

            if ((intRowIndex < 0) || (intRowIndex >= objRows.Count))
            {
                throw new ArgumentOutOfRangeException("rowIndex");
            }

            DataGridViewRow objDataGridViewRow = objRows.SharedRow(intRowIndex);
            DataGridViewElementStates enmRowState = objRows.GetRowState(intRowIndex);
            if (this.IsSharedCellSelected(objDataGridViewRow.Cells[intColumnIndex], intRowIndex) == blnSelected)
            {
                return;
            }
            DataGridViewCell objDataGridViewCell = objRows[intRowIndex].Cells[intColumnIndex];
            DataGridViewIntLinkedList objSelectedBandIndexes = null;
            DataGridViewCellLinkedList objIndividualSelectedCells = this.IndividualSelectedCells;

            if (blnSelected)
            {
                if (((enmRowState & DataGridViewElementStates.Selected) == DataGridViewElementStates.None) && !this.Columns[intColumnIndex].Selected)
                {
                    objIndividualSelectedCells.Add(objDataGridViewCell);
                    this.SetSelectedCellCore(objDataGridViewCell, true, blnClientSource);
                    return;
                }
                return;
            }

            if ((objDataGridViewCell.State & DataGridViewElementStates.Selected) != DataGridViewElementStates.None)
            {
                objIndividualSelectedCells.Remove(objDataGridViewCell);
            }
            else
            {
                DataGridViewCell objCell2;
                bool blnFlag = false;
                if (this.SelectionMode == DataGridViewSelectionMode.ColumnHeaderSelect)
                {
                    if (this.Rows.Count > 8)
                    {
                        this.BulkPaintCount++;
                        blnFlag = true;
                    }
                    try
                    {
                        objSelectedBandIndexes = this.SelectedBandIndexes;
                        objSelectedBandIndexes.Remove(intColumnIndex);
                        this.Columns[intColumnIndex].SelectedInternal = false;

                        for (int i = 0; i < intRowIndex; i++)
                        {
                            objCell2 = objRows[i].Cells[intColumnIndex];
                            this.SetSelectedCellCore(objCell2, true, blnClientSource);
                            objIndividualSelectedCells.Add(objCell2);
                        }
                        for (int j = intRowIndex + 1; j < objRows.Count; j++)
                        {
                            objCell2 = objRows[j].Cells[intColumnIndex];
                            this.SetSelectedCellCore(objCell2, true, blnClientSource);
                            objIndividualSelectedCells.Add(objCell2);
                        }

                        if (objDataGridViewCell.Selected)
                        {
                            this.SetSelectedCellCore(objDataGridViewCell, false, blnClientSource);
                        }

                        return;
                    }
                    finally
                    {
                        if (blnFlag)
                        {
                            this.ExitBulkPaint(intColumnIndex, -1);
                        }
                    }
                }
                if (this.SelectionMode == DataGridViewSelectionMode.RowHeaderSelect)
                {
                    if (this.Columns.Count > 8)
                    {
                        this.BulkPaintCount++;
                        blnFlag = true;
                    }
                    try
                    {
                        if (objSelectedBandIndexes == null)
                        {
                            objSelectedBandIndexes = this.SelectedBandIndexes;
                        }
                        objSelectedBandIndexes.Remove(intRowIndex);
                        objRows.SetRowState(intRowIndex, DataGridViewElementStates.Selected, false);
                        for (int k = 0; k < intColumnIndex; k++)
                        {
                            objCell2 = objRows[intRowIndex].Cells[k];
                            this.SetSelectedCellCore(objCell2, true, blnClientSource);
                            objIndividualSelectedCells.Add(objCell2);
                        }
                        for (int m = intColumnIndex + 1; m < this.Columns.Count; m++)
                        {
                            objCell2 = objRows[intRowIndex].Cells[m];
                            this.SetSelectedCellCore(objCell2, true, blnClientSource);
                            objIndividualSelectedCells.Add(objCell2);
                        }
                    }
                    finally
                    {
                        if (blnFlag)
                        {
                            this.ExitBulkPaint(-1, intRowIndex);
                        }
                    }
                }
            }

            if (objDataGridViewCell.Selected)
            {
                this.SetSelectedCellCore(objDataGridViewCell, false, blnClientSource);
            }
        }

        /// <summary>
        /// Sets the selected cell core.
        /// </summary>
        /// <param name="objDataGridViewCell">The obj data grid view cell.</param>
        /// <param name="blnValue">if set to <c>true</c> [BLN value].</param>
        /// <param name="blnClientSource">if set to <c>true</c> [BLN client source].</param>
        internal void SetSelectedCellCore(DataGridViewCell objDataGridViewCell, bool blnValue, bool blnClientSource)
        {
            if (objDataGridViewCell != null)
            {
                if (!blnClientSource)
                {
                    // if selected state changed them update cell
                    if (((objDataGridViewCell.State & DataGridViewElementStates.Selected) == DataGridViewElementStates.Selected) != blnValue)
                    {
                        objDataGridViewCell.UpdateParams(AttributeType.Visual);
                    }
                }

                objDataGridViewCell.SelectedInternal = blnValue;
            }
        }

        /// <summary>
        /// Gets the member position.
        /// </summary>
        /// <param name="strMember">The STR member.</param>
        /// <returns></returns>
        internal Point GetMemberPosition(string strMember)
        {
            Point objPoint = new Point(-1, -1);

            if (!string.IsNullOrEmpty(strMember))
            {
                //If this is a grid header cell
                if (strMember.Contains("GHC"))
                {
                    //New point with -1 as X and -1 as Y
                    objPoint = new Point(-1, -1);
                }
                //If this is a header cell
                else if (strMember.Contains("HC"))
                {
                    // Get member id.   
                    int intMemberID = int.Parse(strMember.Substring(3));

                    //If this is a row
                    if (strMember.Contains("RHC"))
                    {
                        //New point with -1 as X this is a header cell
                        objPoint = new Point(-1, intMemberID);
                    }
                    else
                    {
                        //New point with -1 as Y this is a header cell
                        objPoint = new Point(intMemberID, -1);
                    }
                }

                //This is a plain cell
                else
                {
                    // Get member id.
                    int intMemberID = int.Parse(strMember.Substring(1));


                    // Get member type.
                    char chrMemberType = strMember[0];

                    switch (chrMemberType)
                    {
                        case 'D':
                            int intRowIndex = (int)Math.Floor((double)(intMemberID / this.ColumnCount));
                            int intColumnIndex = intMemberID - (intRowIndex * this.ColumnCount);
                            objPoint = new Point(intColumnIndex, intRowIndex - (ShowFilterRow && intRowIndex > 0 ? 1 : 0));
                            break;
                        case 'C':
                        case 'R':
                            objPoint = new Point(intMemberID, intMemberID);
                            break;

                    }
                }
            }

            return objPoint;
        }

        /// <summary>
        /// Checks if a string collection has value
        /// </summary>
        /// <param name="arrValues"></param>
        /// <param name="strValue"></param>
        /// <returns></returns>
        private bool HasValue(string[] arrValues, string strValue)
        {
            foreach (string strArrayValue in arrValues)
            {
                if (strArrayValue == strValue)
                {
                    return true;
                }
            }
            return false;
        }

