        private void RenderExtendedColumnHeaderCellUserControls(Gizmox.WebGUI.Common.Interfaces.IContext objContext, Gizmox.WebGUI.Common.Interfaces.IResponseWriter objWriter, long lngRequestID)
        {
            //Create xml element for Extended Header controls
            objWriter.WriteStartElement(WGTags.ExtendedColumnHeaderCollection);

