        /// <summary>
        /// Pre-render control.
        /// </summary>
        /// <param name="objContext">The context.</param>
        /// <param name="lngRequestID">The request ID.</param>
        protected internal override void PreRenderControl(IContext objContext, long lngRequestID)
        {
            if (IsDirty(lngRequestID))
            {
                if (ShouldPreRenderUpdate(PreRenderUpdateType.GroupingData))
                {
                    // Initialize grouping system hierarchies and treeview. Hide grouped columns if needed.
                    InitializeGroupingData();
                }

                if (ShouldPreRenderUpdate(PreRenderUpdateType.GroupHeaders))
                {
                    // Initialize groups and build group headers, if needed.
                    PreRenderGroupingData();
                }

                if (ShouldPreRenderUpdate(PreRenderUpdateType.FilterRow))
                {
                    // Prerender/refresh filter row cells.
                    PreRenderFilterRowCells();
                }
            }

            // Prerenders the top left header cell.
            this.PreRenderTopLeftHeaderCell(objContext, lngRequestID, this.IsDirty(lngRequestID));

            // Pre-render columns.
            PreRenderColumns(objContext, lngRequestID, this.IsDirty(lngRequestID));

            // Pre-render rows.
            PreRenderRows(objContext, lngRequestID, this.IsDirty(lngRequestID));

            base.PreRenderControl(objContext, lngRequestID);

        }

        /// <summary>
        /// Initializes grouping system hierarchies and treeview.
        /// </summary>
        private void InitializeGroupingData()
        {
            ResetDataBinding();

            // If grouping columns should be hidden..
            if (this.HideGroupedColumns)
            {
                UniqueObservableCollection<string> arrGroupingColumns = this.GroupingColumns;

                DataGridViewColumnCollection arrColumns = this.Columns;

                // Iterate and hide columns that appear in GroupingColumns.
                foreach (string strDataPropertyName in arrGroupingColumns)
                {
                    // Get column name
                    string strColumnName = arrColumns.GetRealDataMemberForProposedMember(strDataPropertyName);

                    // Hide column.
                    if (!string.IsNullOrEmpty(strColumnName))
                    {
                        arrColumns[strColumnName].Visible = false;
                    }
                }
            }

            // Create/initialize treeview
            if (this.mobjGroupingTreeView == null)
            {
                this.mobjGroupingTreeView = new DataGridViewGroupingTreeView(this);
            }
            else
            {
                this.mobjGroupingTreeView.InitializeGroupingNodes();
            }

            // Reset dirty flag.
            SwitchPreRenderUpdate(~PreRenderUpdateType.GroupingData);
        }

        /// <summary>
        /// Prerenders filter row cells.
        /// </summary>
        private void PreRenderFilterRowCells()
        {
            InitializeFilterRow();
            SwitchPreRenderUpdate(~PreRenderUpdateType.FilterRow);
        }

