        /// <summary>
        /// Renders the control's meta attributes
        /// </summary>
        /// <param name="objContext">The current VWG Context</param>
        /// <param name="objWriter">The XML stream writer</param>
        protected override void RenderAttributes(IContext objContext, IAttributeWriter objWriter)
        {
            base.RenderAttributes(objContext, objWriter);

            if (IsVirtualDataGridView)
            {
                // Write if Virtual.
                objWriter.WriteAttributeString(WGAttributes.Virtual, "1");
            }

            //Render tab behavior mode
            RenderStandardTabAttribute(objWriter, false);

            // Render ResizeAllRows attribute
            RenderEnforceEqualRowSizeAttribute(objWriter, false);

            // Render IsCaptionVisible attribute
            RenderIsCaptionVisibleAttribute(objWriter, false);

            //Renders the caption height attribute.
            RenderCaptionHeightAttribute(objWriter, false);

            // Render ShowGroupingDropArea attribute.
            RenderShowGroupingDropAreaAttribute(objWriter, false);

            // Render the grouping area style properties.
            RenderGroupingAreaStyleProperties(objWriter, objContext, false);

            // Render cell selection mode.
            objWriter.WriteAttributeString(WGAttributes.SelectionMode, ((int)this.SupportedSelectionMode).ToString());

            // Renders the text attribute.
            RenderTextAttribute(objWriter, false);

            RenderDisableNavigation(objWriter, false);

            RenderScrollbarsAttribute(objWriter, false);

            RenderCurrentCell(objContext, objWriter, false);

            if (this.IsHierarchic(HierarchicInfoSelector.Any))
            {
                RenderHierarchicAttributes(objWriter);
            }

            objWriter.WriteAttributeString(WGAttributes.DataGridViewHierarchyLevel, this.mintHierarchyLevel.ToString());

            // Render paging information.
            objWriter.WriteAttributeString(WGAttributes.CurrentPage, this.CurrentPage.ToString());
            objWriter.WriteAttributeString(WGAttributes.TotalPages, this.TotalPages.ToString());

            RenderMultiSelect(objWriter, false);

            // Render the ShowEditingIcon attribute.
            RenderShowEditingIcon(objWriter, false);

            if (!this.RowHeadersVisible)
            {
                objWriter.WriteAttributeString(WGAttributes.RowHeaders, "0");
            }
            else
            {
                objWriter.WriteAttributeString(WGAttributes.RowHeaders, this.RowHeadersWidth.ToString());
            }

            if (!this.ColumnHeadersVisible)
            {
                objWriter.WriteAttributeString(WGAttributes.ColumnHeaders, "0");
            }
            else
            {
                objWriter.WriteAttributeString(WGAttributes.ColumnHeaders, this.ColumnHeadersHeight.ToString());
            }

            if (this.CellBorderStyle != DataGridViewCellBorderStyle.Single)
            {
                objWriter.WriteAttributeString(WGAttributes.CellBorderStyle, ((byte)this.CellBorderStyle).ToString());
            }

            // Render read only attribute - if needed.
            if (this.ReadOnly)
            {
                objWriter.WriteAttributeString(WGAttributes.ReadOnly, "1");
            }

            // Check if grid is virtual.
            if (this.IsVirtualDataGridView)
            {
                // Write the number of rows.
                objWriter.WriteAttributeString(WGAttributes.RowCount, (this.Rows.Count + (this.ShowFilterRow ? 1 : 0)).ToString());

                // Calculate a virtual block size.
                int intVirtualBlockSize = (this.UseInternalPaging ? this.ItemsPerPage : this.VirtualBlockSize);

                // Write the virtual block size.
                objWriter.WriteAttributeString(WGAttributes.VirtualBlockSize, intVirtualBlockSize.ToString());
            }

            RenderColumnsCount(objWriter);

            RenderAllowUserToOrderColumns(objWriter, false);

            RenderSelectOnRightClick(objWriter, false);

            // Render edit mode attribute
            RenderEditModeAttribute(objWriter, false);

            RenderShowColumnChooserAttribute(objWriter, false);

            /// Renders the navigation key filter attribute.
            RenderNavigationKeyFilterAttribute(objWriter, false);
        }

        /// <summary>
        /// Renders the navigation key filter attribute.
        /// </summary>
        /// <param name="objWriter">The obj writer.</param>
        /// <param name="blnForceRender">if set to <c>true</c> [BLN force render].</param>
        private void RenderNavigationKeyFilterAttribute(IAttributeWriter objWriter, bool blnForceRender)
        {
            if (menmNavigationKeyFilter != NavigationKeyFilter.None || blnForceRender)
            {
                objWriter.WriteAttributeString(WGAttributes.NavigationKeyFilter, ((int)menmNavigationKeyFilter).ToString());
            }
        }

        /// <summary>
        /// Renders the grouping area style properties.
        /// </summary>
        /// <param name="objWriter">The obj writer.</param>
        /// <param name="objContext">The obj context.</param>
        /// <param name="blnForceRender">if set to <c>true</c> [BLN force render].</param>
        private void RenderGroupingAreaStyleProperties(IAttributeWriter objWriter, IContext objContext, bool blnForceRender)
        {
            DataGridViewSkin objSkin = SkinFactory.GetSkin(this) as DataGridViewSkin;

            if (objSkin != null)
            {
                // If backColor should be rendered..
                if (this.GroupingAreaStyleProperties.BackColor != objSkin.GroupingDropAreaStyle.BackColor || blnForceRender)
                {
                    objWriter.WriteAttributeText(WGAttributes.GroupingAreaBackColor, CommonUtils.GetHtmlColor(this.GroupingAreaBackColor));
                }

                // if border should be rendered
                if (this.ShouldRenderGroupingAreaBorder(objSkin) || blnForceRender)
                {
                    // Render the border style to the client
                    BorderValue objBorderValue = new BorderValue();
                    objBorderValue.Width = this.GroupingAreaBorderWidth;
                    objBorderValue.Color = this.GroupingAreaBorderColor;
                    objBorderValue.Style = this.GroupingAreaBorderStyle;

                    // Render the border according to the specific presentation layer
                    objWriter.WriteAttributeString(WGAttributes.GroupingAreaBorder, objBorderValue.GetValue(objContext));
                }

                // If background image should be rendered
                if (GroupingAreaBackgroundImage != null)
                {
                    objWriter.WriteAttributeString(WGAttributes.GroupingAreaBackgroundImage, GroupingAreaBackgroundImage.ToString());
                }

                // If background image position should be rendered
                if (ShouldRenderGroupingAreaBackgroundImagePosition(objSkin) || blnForceRender)
                {
                    objWriter.WriteAttributeString(WGAttributes.GroupingAreaBackgroundImagePosition, (int)GroupingAreaBackgroundImagePosition);
                }

                // If background image repeat should be rendered
                if (ShouldRenderGroupingAreaBackgroundImageRepeat(objSkin) || blnForceRender)
                {
                    objWriter.WriteAttributeString(WGAttributes.GroupingAreaBackgroundImageRepeat, (int)GroupingAreaBackgroundImageRepeat);
                }

                // If height should be rendered..
                if (ShouldRenderGroupingAreaHeight(objSkin) || blnForceRender)
                {
                    objWriter.WriteAttributeString(WGAttributes.DropAreaHeight, GroupingAreaHeight);
                }
            }
        }

        /// <summary>
        /// Defines whether to render grouping area border.
        /// </summary>
        /// <param name="objSkin">The obj skin.</param>
        /// <returns></returns>
        private bool ShouldRenderGroupingAreaBorder(DataGridViewSkin objSkin)
        {
            return this.GroupingAreaBorderColor != objSkin.GroupingDropAreaStyle.BorderColor &&
                    this.GroupingAreaBorderStyle != objSkin.GroupingDropAreaStyle.BorderStyle &&
                    this.GroupingAreaBorderWidth != objSkin.GroupingDropAreaStyle.BorderWidth;
        }
        /// <summary>
        ///  Defines whether to render grouping area background image repeat.
        /// </summary>
        /// <param name="objSkin">The obj skin.</param>
        /// <returns></returns>
        private bool ShouldRenderGroupingAreaBackgroundImageRepeat(DataGridViewSkin objSkin)
        {
            return this.GroupingAreaBackgroundImageRepeat != objSkin.GroupingDropAreaStyle.BackgroundImageRepeat;
        }

        /// <summary>
        /// Defines whether to render grouping area height.
        /// </summary>
        /// <param name="objSkin">The obj skin.</param>
        /// <returns></returns>
        private bool ShouldRenderGroupingAreaHeight(DataGridViewSkin objSkin)
        {
            return this.GroupingAreaHeight != objSkin.DropAreaHeight;
        }

        /// <summary>
