        /// <summary>
        /// Renders only the control's updated meta attributes
        /// </summary>
        /// <param name="objContext">The current VWG Context</param>
        /// <param name="objWriter">The XML stream writer</param>
        /// <param name="lngRequestID">The ID of the request currently being handled</param>
        protected override void RenderUpdatedAttributes(IContext objContext, IAttributeWriter objWriter, long lngRequestID)
        {
            base.RenderUpdatedAttributes(objContext, objWriter, lngRequestID);

            // Render Control's Attributes
            if (IsDirtyAttributes(lngRequestID, AttributeType.Control))
            {
                RenderAllowUserToOrderColumns(objWriter, true);
                RenderDisableNavigation(objWriter, true);
                RenderMultiSelect(objWriter, true);
                RenderStandardTabAttribute(objWriter, true);
                RenderSelectOnRightClick(objWriter, true);

                // Render edit mode attribute
                RenderEditModeAttribute(objWriter, true);

                // Renders the text attribute.
                RenderTextAttribute(objWriter, true);

                // Renders the Expansion Indicator attribute.
                RenderExpansionIndicator(objWriter, true);

                // Renders the Show Column Chooser attribute.
                RenderShowColumnChooserAttribute(objWriter, true);

                // Render the ShowEditingIcon attribute.
                RenderShowEditingIcon(objWriter, true);

                /// Renders the navigation key filter attribute.
                RenderNavigationKeyFilterAttribute(objWriter, true);
            }

            // Render Visual Attributes
            if (IsDirtyAttributes(lngRequestID, AttributeType.Visual))
            {
                objWriter.WriteAttributeString(WGAttributes.CellBorderStyle, ((byte)this.CellBorderStyle).ToString());

                RenderCurrentCell(objContext, objWriter, true);

                // Render grouping area style properties.
                RenderGroupingAreaStyleProperties(objWriter, objContext, true);
            }

            //Render Events Attributes
            if (IsDirtyAttributes(lngRequestID, AttributeType.Layout))
            {
                // Render EnforceEqualRowSize attribute
                RenderEnforceEqualRowSizeAttribute(objWriter, true);

                // Render IsCaptionVisible attribute
                RenderIsCaptionVisibleAttribute(objWriter, true);

                // Render ShowGroupingDropArea attribute
                RenderShowGroupingDropAreaAttribute(objWriter, true);

                //Render RenderScrollbarsAttribute
                RenderScrollbarsAttribute(objWriter, true);

                //Renders the caption height attribute.
                RenderCaptionHeightAttribute(objWriter, true);                
            }
        }

