        /// <summary>
        /// Renders the caption height attribute.
        /// </summary>
        /// <param name="objWriter">The obj writer.</param>
        /// <param name="blnForceRender">if set to <c>true</c> [BLN force render].</param>
        private void RenderCaptionHeightAttribute(IAttributeWriter objWriter, bool blnForceRender)
        {
            if (this.IsCaptionVisible)
            {
                // Get aplicative caption height
                int intCaptionHeight = this.CaptionHeight;

                // Check if value set
                if (intCaptionHeight == 0)
                {
                    DataGridViewSkin objSkin = this.Skin as DataGridViewSkin;
                    if (objSkin != null)
                    {
                        StyleValue objCaptionStyle = objSkin.CaptionStyle;

                        intCaptionHeight = CommonUtils.GetFontHeight(objCaptionStyle.Font) + objCaptionStyle.Padding.Vertical;
                    }
                }

                objWriter.WriteAttributeString(WGAttributes.CaptionHeight, intCaptionHeight.ToString());
            }
        }

