        /// <summary>
        /// Renders the controls sub tree
        /// </summary>
        /// <param name="objContext"></param>
        /// <param name="objWriter"></param>
        /// <param name="lngRequestID"></param>
        protected override void RenderControls(Gizmox.WebGUI.Common.Interfaces.IContext objContext, Gizmox.WebGUI.Common.Interfaces.IResponseWriter objWriter, long lngRequestID)
        {
            // Members should render owner there controls only if owner did not render it self.            
            bool blnRenderOwner = !this.IsDirty(lngRequestID);

            //Render extended header control
            this.RenderExtendedColumnHeader(objContext, objWriter, lngRequestID, blnRenderOwner);

            // Render grouping drop area.
            this.RenderGroupingDropArea(objContext, objWriter, lngRequestID);

            // Renders the top left header cell.
            this.RenderTopLeftHeaderCell(objContext, objWriter, lngRequestID, blnRenderOwner);

            // Render columns.
            this.RenderColumns(objContext, objWriter, lngRequestID, blnRenderOwner);

            // Render rows.
            this.RenderRows(objContext, objWriter, lngRequestID, blnRenderOwner);

        }

