        /// <summary>
        /// Pres the render columns.
        /// </summary>
        /// <param name="objContext">The context.</param>
        /// <param name="lngRequestID">The request ID.</param>
        /// <param name="blnForcePreRender">if set to <c>true</c> [BLN force pre render].</param>
        private void PreRenderColumns(IContext objContext, long lngRequestID, bool blnForcePreRender)
        {
            // Get first column.
            DataGridViewColumn objDataGridViewColumn = this.Columns.GetFirstColumn(DataGridViewElementStates.Visible);

            // Loops while having a valid column.
            while (objDataGridViewColumn != null)
            {
                // Pre-render current column.
                objDataGridViewColumn.PreRenderComponent(objContext, lngRequestID, blnForcePreRender);

                // Get next column.
                objDataGridViewColumn = this.Columns.GetNextColumn(objDataGridViewColumn, DataGridViewElementStates.Visible, DataGridViewElementStates.None);
            }
        }

