        /// Posts the render columns.
        /// </summary>
        /// <param name="objContext">The obj context.</param>
        /// <param name="lngRequestID">The LNG request ID.</param>
        /// <param name="blnForcePostRender">if set to <c>true</c> [BLN force post render].</param>
        private void PostRenderColumns(IContext objContext, long lngRequestID, bool blnForcePostRender)
        {
            // Get first column.
            DataGridViewColumn objDataGridViewColumn = this.Columns.GetFirstColumn(DataGridViewElementStates.Visible);

            // Loops while having a valid column.
            while (objDataGridViewColumn != null)
            {
                // Post-render current column.
                objDataGridViewColumn.PostRenderComponent(objContext, lngRequestID, blnForcePostRender);

                // Get next column.
                objDataGridViewColumn = this.Columns.GetNextColumn(objDataGridViewColumn, DataGridViewElementStates.Visible, DataGridViewElementStates.None);
            }
        }

