        /// <summary>
        /// Pres the render rows.
        /// </summary>
        /// <param name="objContext">The context.</param>
        /// <param name="lngRequestID">The request ID.</param>
        /// <param name="blnForcePreRender">if set to <c>true</c> [BLN force pre render].</param>
        private void PreRenderRows(IContext objContext, long lngRequestID, bool blnForcePreRender)
        {
            bool blnContainsFrozeRows = false;

            // Get paged rows.
            IList objPagedRows = GetRows(out blnContainsFrozeRows);
            if (objPagedRows != null)
            {
                // Loop all paged rows.
                foreach (DataGridViewRow objDataGridViewRow in objPagedRows)
                {
                    // Render current row.
                    objDataGridViewRow.PreRenderComponent(objContext, lngRequestID, blnForcePreRender);
                }
            }
        }

        /// <summary>
        /// Posts the render rows.
        /// </summary>
        /// <param name="objContext">The obj context.</param>
        /// <param name="lngRequestID">The LNG request ID.</param>
        /// <param name="blnForcePostRender">if set to <c>true</c> [BLN force post render].</param>
        private void PostRenderRows(IContext objContext, long lngRequestID, bool blnForcePostRender)
        {
            bool blnContainsFrozeRows = false;

            // Get paged rows.
            IList objPagedRows = GetRows(out blnContainsFrozeRows);
            if (objPagedRows != null)
            {
                // Loop all paged rows.
                foreach (DataGridViewRow objDataGridViewRow in objPagedRows)
                {
                    // Render current row.
                    objDataGridViewRow.PostRenderComponent(objContext, lngRequestID, blnForcePostRender);
                }
            }
        }

        /// <summary>
        /// Checks whether filter row should be processed.
        /// </summary>
        /// <returns></returns>
        private bool ShouldProcessFilterRow()
        {
            return this.ShowFilterRow && mobjDataGridViewFilterRow != null && this.Columns.GetColumnCount(DataGridViewElementStates.Visible) > 0;
        }

        /// <summary>
        /// Gets the rows.
        /// </summary>
        /// <param name="blnContainsFrozeRows">if set to <c>true</c> [BLN contains froze rows].</param>
        /// <returns></returns>
        private IList GetRows(out bool blnContainsFrozeRows)
        {
            // Get Current PageRows
            IList objPagedRows = this.GetPagedRows(out blnContainsFrozeRows);

            // If filtering is ON, insert filter row as 1st row in rows collection.
            if (ShouldProcessFilterRow())
            {
                int intNewRowArrayDimension = objPagedRows.Count + 1;

                // Reserve array.
                DataGridViewRow[] arrDataGridViewRow = new DataGridViewRow[intNewRowArrayDimension];

                // Set filter row at 1st index.
                arrDataGridViewRow[0] = mobjDataGridViewFilterRow;

                // Assign data rows.
                for (int intRowCount = 1; intRowCount < intNewRowArrayDimension; intRowCount++)
                {
                    arrDataGridViewRow[intRowCount] = objPagedRows[intRowCount - 1] as DataGridViewRow;
                }

                // Create IList-compatible container. 
                objPagedRows = new List<DataGridViewRow>(arrDataGridViewRow);

                // Filter row is always frozen.
                blnContainsFrozeRows = true;
            }

            // Get the Grid Rows
            DataGridViewRowCollection objRows = this.Rows;

            // Validate new row index.
            if (this.NewRowIndex >= 0 && this.NewRowIndex < objRows.Count)
            {
                // Get shared new row.
                DataGridViewRow objNewRow = objRows[this.NewRowIndex];

                // Check that new row is not nul and that it is not already contained in the paged rows collection.
                if (objNewRow != null && !objPagedRows.Contains(objNewRow))
                {
                    // Add the shared new row.
                    objPagedRows.Add(objNewRow);
                }
            }
            return objPagedRows;
        }

        /// <summary>
        /// Renders the datagridview rows.
        /// </summary>
        /// <param name="objContext">The obj context.</param>
        /// <param name="objWriter">The obj writer.</param>
        /// <param name="lngRequestID">The LNG request ID.</param>
        protected void RenderRows(Gizmox.WebGUI.Common.Interfaces.IContext objContext, Gizmox.WebGUI.Common.Interfaces.IResponseWriter objWriter, long lngRequestID, bool blnRenderOwner)
        {
            if (this.IsVirtualDataGridView)
            {
                // In case of full rendering.
                if (lngRequestID == 0)
                {
                    // Validate local blocks manager.
                    if (mobjDataGridViewBlocksManager != null)
                    {
                        // Clear manager's blocks information cache.
                        mobjDataGridViewBlocksManager.ClearBlockInfoCache();
                    }
                }

                // Define blocks top position indicatior.
                int intBlockTopPosition = 0;

                // Get scroll top position.
                int intScrollTopPosition = this.ScrollTop;

                // Get grid's height.
                int intHeight = this.Height;

                // Loop all blocks.
                foreach (DataGridRowBlock objRowBlock in this.GetRowBlocks())
                {
                    // Render current block.
                    objRowBlock.RenderBlock(objContext, objWriter, lngRequestID, blnRenderOwner, this.IsDirty(lngRequestID), intBlockTopPosition, intScrollTopPosition, intHeight);

                    // Raise the blocks top position indicatior according to current block height.
                    intBlockTopPosition += objRowBlock.BlockHeight;
                }
            }
            else
            {
                bool blnContainsFrozeRows = false;

                // Get paged rows.
                IList objPagedRows = GetRows(out blnContainsFrozeRows);
                if (objPagedRows != null)
                {
                    // Loop all paged rows.
                    foreach (DataGridViewRow objDataGridViewRow in objPagedRows)
                    {
                        // Check row visibility
                        if (objDataGridViewRow.Visible)
                        {
                            // Render current row.
                            ((IRenderableComponentMember)objDataGridViewRow).RenderComponent(objContext, objWriter, lngRequestID, blnRenderOwner);
                        }
                    }
                }
            }
        }

        /// <summary>
        /// Gets the row blocks.
        /// </summary>
        /// <returns></returns>
        private IEnumerable<DataGridRowBlock> GetRowBlocks()
        {
            List<DataGridRowBlock> arrRowBlocks = new List<DataGridRowBlock>();

            // Define a switch which will indicate if current block contains frozen rows.
            bool blnContainsFrozenRows = false;

            // Get paged rows.
            IList objPagedRows = GetRows(out blnContainsFrozenRows);
            if (objPagedRows != null)
            {
                // Check if paging is enabled.
                if (this.UseInternalPaging)
                {
                    // Add one block with all paged rows.
                    arrRowBlocks.Add(new DataGridRowBlock(this, objPagedRows, 1, blnContainsFrozenRows));
                }
                else
                {
                    // Define a block rows array.
                    List<DataGridViewRow> arrBlockRows = new List<DataGridViewRow>();

                    // Initialize switch.
                    blnContainsFrozenRows = false;

                    // Loop all paged rows.
                    for (int intRowIndex = 0; intRowIndex < objPagedRows.Count; intRowIndex++)
                    {
                        // Check if block rows are in the reqiered virtual block size.
                        if (arrBlockRows.Count == this.VirtualBlockSize)
                        {
                            // Add a new block with the current row to block rows array.
                            arrRowBlocks.Add(new DataGridRowBlock(this, arrBlockRows, arrRowBlocks.Count + 1, blnContainsFrozenRows));

                            // Create a new block rows array.
                            arrBlockRows = new List<DataGridViewRow>();

                            // Initialize switch.
                            blnContainsFrozenRows = false;
                        }

                        // Get current row.
                        DataGridViewRow objDataGridViewRow = objPagedRows[intRowIndex] as DataGridViewRow;
                        if (objDataGridViewRow != null && objDataGridViewRow.GetVisible(objDataGridViewRow.Index))
                        {
                            // Check if current row is frozen.
                            if (objDataGridViewRow.Frozen)
