                                blnContainsFrozenRows = true;
                            }

                            // Add current row to block rows array.
                            arrBlockRows.Add(objDataGridViewRow);
                        }
                    }

                    // Check if the block rows array contains rows.
                    if (arrBlockRows.Count > 0)
