        /// <summary>
        /// Handles the ClosedForColumnVisibility event of the DataGridView control.
        /// </summary>
        /// <param name="sender">The source of the event.</param>
        /// <param name="e">The <see cref="System.EventArgs"/> instance containing the event data.</param>
        private void DataGridView_ClosedForColumnVisibility(object sender, EventArgs e)
        {
            ColumnChooserDialog objDialog = (sender as ColumnChooserDialog);

            if (objDialog != null && objDialog.DialogResult == DialogResult.OK)
            {
                UpdateColumnsVisibility(objDialog);
            }
        }

        /// <summary>
        /// Updates the columns visibility according to the column chooser.
        /// </summary>
        /// <param name="objDialog">The obj dialog.</param>
        internal virtual void UpdateColumnsVisibility(ColumnChooserDialog objDialog)
        {
            // Iterate through the Root level
            foreach (KeyValuePair<DataGridViewColumn, ColumnCheckedStatus> objColumnState in objDialog.ChosenRootColumns)
            {
                DataGridViewColumn objColumn = objColumnState.Key;

                if (objColumn != null)
                {
                    List<DataGridViewColumn> objChangedColumns = new List<DataGridViewColumn>();
                    // Change column visibility only if really changed in the column chooser
                    if (objColumnState.Value.IsChanged)
                    {
                        // Change visibility according to the checked state
                        objColumn.Visible = objColumnState.Value.IsChecked;

                        objChangedColumns.Add(objColumn);
                    }

                    this.OnColumnChooserColumnsVisibilityChanged(objChangedColumns);
                }
            }

            // Update children
            UpdateChildGridColumnsVisibility(objDialog);
        }

        /// <summary>
        /// Updates the child grid columns visibility.
        /// </summary>
        /// <param name="objDialog">The obj dialog.</param>
        internal void UpdateChildGridColumnsVisibility(ColumnChooserDialog objDialog)
        {
            // Check whether this grid is hierarchic to perform hierarchic column visibility logic
            if (this.IsHierarchic(HierarchicInfoSelector.Public))
            {
                // Iterate through the hierarchic levels
                foreach (HierarchicInfo objInfo in objDialog.ChosenColumnsIndexByTheirHierarchy.Keys)
                {
                    UpdateSingleHierarchyColumnsVisibility(objInfo, objDialog.ChosenColumnsIndexByTheirHierarchy[objInfo]);
                }
            }
        }

        /// <summary>
        /// Updates the single hierarchy columns visibility.
        /// </summary>
        /// <param name="objInfo">The obj info.</param>
        /// <param name="objColumnsState">The list.</param>
        internal void UpdateSingleHierarchyColumnsVisibility(HierarchicInfo objInfo, List<KeyValuePair<DataGridViewColumn, ColumnCheckedStatus>> objColumnsState)
        {
            List<string> objVisibleItems = new List<string>();
            List<string> objNotVisibleItems = new List<string>();

            // Iterate through every node in this level
            foreach (KeyValuePair<DataGridViewColumn, ColumnCheckedStatus> objColumnState in objColumnsState)
            {
                if (objColumnState.Value.IsChanged)
                {
                    if (objColumnState.Value.IsChecked)
                    {
                        objVisibleItems.Add(objColumnState.Key.Name);
                    }
                    else
                    {
                        objNotVisibleItems.Add(objColumnState.Key.Name);
                    }
                }
            }

            UpdateHierarchyInfosColumnsVisibility(objInfo, objVisibleItems, objNotVisibleItems);
        }

        /// <summary>
        /// Updates the hierarchy infos columns visibility.
        /// </summary>
        /// <param name="objInfo">The obj info.</param>
        /// <param name="objVisibleItems">The obj visible items.</param>
        /// <param name="objNotVisibleItems">The obj not visible items.</param>
        private static void UpdateHierarchyInfosColumnsVisibility(HierarchicInfo objInfo, List<string> objVisibleItems, List<string> objNotVisibleItems)
        {
            // Suspend the OnCollectionChanged event
            objInfo.HiddenColumns.SuspendCollectionChangeNotification();

            // Add all items that should be invisible
            objInfo.HiddenColumns.AddRange(objNotVisibleItems);

            // Remove all items that should be visible
            objInfo.HiddenColumns.RemoveRange(objVisibleItems);

            // Resume imvoking the notification change events (and invoke it now)
            objInfo.HiddenColumns.ResumeCollectionChangeNotification(true);
        }

        /// <summary>
        /// Updates the single hierarchy columns visibility.
        /// </summary>
        /// <param name="objInfo">The obj info.</param>
        /// <param name="objColumnsState">The list.</param>
        internal void UpdateSingleHierarchyColumnsVisibility(HierarchicInfo objInfo, List<KeyValuePair<string, ColumnCheckedStatus>> objColumnsState)
        {
            List<string> objVisibleItems = new List<string>();
            List<string> objNotVisibleItems = new List<string>();

            // Iterate through every node in this level
            foreach (KeyValuePair<string, ColumnCheckedStatus> objColumnState in objColumnsState)
            {
                if (objColumnState.Value.IsChanged)
                {
                    if (objColumnState.Value.IsChecked)
                    {
                        objVisibleItems.Add(objColumnState.Key);
                    }
                    else
