        /// <summary>
        /// Updates the state of the rows displayed.
        /// </summary>
        /// <param name="blnDisplayed">if set to <c>true</c> [displayed].</param>
        private void UpdateRowsDisplayedState(bool blnDisplayed)
        {
            int intFirstDisplayedScrollingRow;
            DisplayedBandsData objDisplayedBandsInfo = this.DisplayedBandsInfo;

            int numDisplayedFrozenRows = objDisplayedBandsInfo.NumDisplayedFrozenRows;

            // Get the Grid Rows
            DataGridViewRowCollection objRows = this.Rows;

            if (numDisplayedFrozenRows > 0)
            {
                intFirstDisplayedScrollingRow = objRows.GetFirstRow(DataGridViewElementStates.Visible | DataGridViewElementStates.Frozen);
                while (numDisplayedFrozenRows > 0)
                {
                    if (((objRows.GetRowState(intFirstDisplayedScrollingRow) & DataGridViewElementStates.Displayed) == DataGridViewElementStates.None) == blnDisplayed)
                    {
                        objRows.SetRowState(intFirstDisplayedScrollingRow, DataGridViewElementStates.Displayed, blnDisplayed);
                    }
                    intFirstDisplayedScrollingRow = objRows.GetNextRow(intFirstDisplayedScrollingRow, DataGridViewElementStates.Visible | DataGridViewElementStates.Frozen);
                    numDisplayedFrozenRows--;
                }
            }
            intFirstDisplayedScrollingRow = objDisplayedBandsInfo.FirstDisplayedScrollingRow;
            if (intFirstDisplayedScrollingRow > -1)
            {
                for (int i = objDisplayedBandsInfo.NumDisplayedScrollingRows; i > 0; i--)
                {
                    if (((objRows.GetRowState(intFirstDisplayedScrollingRow) & DataGridViewElementStates.Displayed) == DataGridViewElementStates.None) == blnDisplayed)
                    {
                        objRows.SetRowState(intFirstDisplayedScrollingRow, DataGridViewElementStates.Displayed, blnDisplayed);
                    }
                    intFirstDisplayedScrollingRow = objRows.GetNextRow(intFirstDisplayedScrollingRow, DataGridViewElementStates.Visible);
                }
            }
        }

