        /// <summary>Raises the <see cref="E:Gizmox.WebGUI.Forms.DataGridView.ColumnStateChanged"></see> event.</summary>
        /// <param name="e">A <see cref="T:Gizmox.WebGUI.Forms.DataGridViewColumnStateChangedEventArgs"></see> that contains the event data. </param>
        /// <exception cref="T:System.InvalidCastException">The column changed from read-only to read/write, enabling the current cell to enter edit mode, but the <see cref="P:Gizmox.WebGUI.Forms.DataGridViewCell.EditType"></see> property of the current cell does not indicate a class that derives from <see cref="T:Gizmox.WebGUI.Forms.Control"></see> and implements <see cref="T:Gizmox.WebGUI.Forms.IDataGridViewEditingControl"></see>.</exception>
        protected virtual void OnColumnStateChanged(DataGridViewColumnStateChangedEventArgs e)
        {
            // column.Frozen | .Visible changed - this may require a complete re-layout of the control
            DataGridViewColumn objDataGridViewColumn = e.Column;
            switch (e.StateChanged)
            {
                // At this point we assume that only the Selected state has an influence on the rendering of the column.
                // If there is a customer scenario where another state has an influence, the dev must invalidate the column by hand. 
                // case DataGridViewElementStates.ReadOnly: 
                // case DataGridViewElementStates.Resizable:

                case DataGridViewElementStates.Selected:
                    if (objDataGridViewColumn.Visible && this.BulkPaintCount == 0)
                    {
                        InvalidateColumnInternal(objDataGridViewColumn.Index);
                    }
                    break;

                case DataGridViewElementStates.Frozen:
                    if (objDataGridViewColumn.Visible)
                    {
                        // UsedFillWeight values need to be updated 
                        this.mobjDataGridViewState2[DATAGRIDVIEWSTATE2_usedFillWeightsDirty] = true;

                        PerformLayoutPrivate(true);
                        Invalidate();
                    }
                    break;

                case DataGridViewElementStates.Visible:
                    if (!objDataGridViewColumn.Visible && objDataGridViewColumn.Displayed)
                    {
                        // Displayed column becomes invisible. Turns off the Displayed state. 
                        objDataGridViewColumn.DisplayedInternal = false;
                    }

                    // UsedFillWeight values need to be updated 
                    this.mobjDataGridViewState2[DATAGRIDVIEWSTATE2_usedFillWeightsDirty] = true;

                    PerformLayoutPrivate(true);
                    DataGridViewAutoSizeRowsMode enmAutoSizeRowsMode = this.AutoSizeRowsMode;
                    bool blnAutoSizeRows = (((DataGridViewAutoSizeRowsModeInternal)enmAutoSizeRowsMode) & DataGridViewAutoSizeRowsModeInternal.AllColumns) != 0 ||
                                        ((((DataGridViewAutoSizeRowsModeInternal)enmAutoSizeRowsMode) & DataGridViewAutoSizeRowsModeInternal.Header) != 0 &&
                                        this.RowHeadersVisible);
                    bool blnAutoSizeColumn = false;
                    DataGridViewAutoSizeColumnMode enmAutoSizeColumnMode = objDataGridViewColumn.InheritedAutoSizeMode;

                    if (enmAutoSizeColumnMode != DataGridViewAutoSizeColumnMode.None &&
                        enmAutoSizeColumnMode != DataGridViewAutoSizeColumnMode.Fill)
                    {
                        // Column autosizes 
                        int intWidth = objDataGridViewColumn.ThicknessInternal;
                        if (objDataGridViewColumn.Visible)
                        {
                            // Cache column's width before potential autosizing occurs 
                            objDataGridViewColumn.CachedThickness = intWidth;
                            AutoResizeColumnInternal(objDataGridViewColumn.Index, (DataGridViewAutoSizeColumnCriteriaInternal)enmAutoSizeColumnMode, !blnAutoSizeRows /*fixedHeight*/);
                            blnAutoSizeColumn = true;
                        }
                        else if (intWidth != objDataGridViewColumn.CachedThickness)
                        {
                            // Columns that are made invisible in the collection take their non-autosized width
                            objDataGridViewColumn.ThicknessInternal = Math.Max(objDataGridViewColumn.MinimumWidth, objDataGridViewColumn.CachedThickness);
                        }
                    }

                    if (blnAutoSizeRows)
                    {
                        if (objDataGridViewColumn.Visible)
                        {
                            AdjustExpandingRows(objDataGridViewColumn.Index, true /*fixedWidth*/);
                        }
                        else
                        {
                            AdjustShrinkingRows(enmAutoSizeRowsMode, true /*fixedWidth*/, true /*internalAutosizing*/);
                        }
                        if (blnAutoSizeColumn)
                        {
                            // Second round of column autosizing
                            AutoResizeColumnInternal(objDataGridViewColumn.Index, (DataGridViewAutoSizeColumnCriteriaInternal)enmAutoSizeColumnMode, true /*fixedHeight*/);
                        }
                    }
                    else
                    {
                        Invalidate();
                    }
                    break;
            }

            // Raise event if needed
            DataGridViewColumnStateChangedEventHandler objEventHandler = this.ColumnStateChanged;
            if (objEventHandler != null)
            {
                objEventHandler(this, e);
            }


            if (e.StateChanged == DataGridViewElementStates.ReadOnly &&
                objDataGridViewColumn.Index == mobjCurrentCellPoint.X &&
                !this.mobjDataGridViewOper[DATAGRIDVIEWOPER_inReadOnlyChange])
            {
                if (!objDataGridViewColumn.ReadOnly &&
                    ColumnEditable(mobjCurrentCellPoint.X) &&
                    (this.Rows.GetRowState(mobjCurrentCellPoint.Y) & DataGridViewElementStates.ReadOnly) == 0 &&
                     !this.IsCurrentCellInEditMode &&
                     (this.EditMode == DataGridViewEditMode.EditOnEnter ||
                      (this.EditMode != DataGridViewEditMode.EditProgrammatically && this.CurrentCellInternal.EditType == null)))
                {
                    // Current column becomes read/write. Enter editing mode. 
                    BeginEditInternal(true /*selectAll*/);
                }
            }

        }

