        /// <summary>
        /// Called when [data binding complete].
        /// </summary>
        /// <param name="enmListChangedType">Type of the list changed.</param>
        internal void OnDataBindingComplete(ListChangedType enmListChangedType)
        {
            this.OnDataBindingComplete(new DataGridViewBindingCompleteEventArgs(enmListChangedType));

            // If data source was reset as result of rebinding, init filter row, when needed.
            if (enmListChangedType == ListChangedType.Reset &&
                this.ShowFilterRow &&
                !this.mblnSuspendFilterInitialization)
            {
                SwitchPreRenderUpdate(PreRenderUpdateType.FilterRow);
            }

            SwitchPreRenderUpdate(PreRenderUpdateType.GroupHeaders);
        }

        /// <summary>
        /// Gets the column header info.
        /// </summary>
        /// <param name="objDataGridViewColumn">The obj data grid view column.</param>
        /// <returns></returns>
        internal HeaderFilterInfo GetColumnHeaderInfo(DataGridViewColumn objDataGridViewColumn)
        {
            List<HeaderFilterInfo> objHeadersFilterInfo = this.mobjHeadersFilterInfo;
            if (objHeadersFilterInfo != null)
            {
                // Loop on all HeadersFilterInfo and find one relevant to the specified column
                foreach (HeaderFilterInfo objHeaderFilterInfo in objHeadersFilterInfo)
                {
                    if (objHeaderFilterInfo.DataPropertyName == objDataGridViewColumn.DataPropertyName)
                    {
                        return objHeaderFilterInfo;
                    }
                }
            }
            return null;
        }

        /// <summary>
        /// Initializes the grouping data.
        /// </summary>
        private void PreRenderGroupingData()
        {
            // Build Groups, if bound to sortable binding source.
            BindingSource objBindingSource = this.DataSource as BindingSource;
            if (objBindingSource != null && objBindingSource.SupportsSorting)
            {
                if (this.GroupingColumns.Count > 0)
                {
                    // Get column data.
                    string strColumnDataPropertyName = this.GroupingColumns[0];
                    string strColumnName = this.Columns.GetRealDataMemberForProposedMember(strColumnDataPropertyName);

                    if (!string.IsNullOrEmpty(strColumnName) && !string.IsNullOrEmpty(strColumnDataPropertyName))
                    {
                        // Get local grouping column.
                        DataGridViewColumn objLocalGroupingColumn = this.Columns[strColumnName];

                        if (!objLocalGroupingColumn.CanGroupBy)
                        {
                            throw new InvalidOperationException(SR.GetString("DataGridView_CannotGroupByThisColumn", new object[] { objLocalGroupingColumn.HeaderText }));
                        }

                        if (objLocalGroupingColumn != null)
                        {
                            if (this.SortedColumn != objLocalGroupingColumn || this.SortOrder != Forms.SortOrder.Ascending)
                            {
                                // Sort rows by column, ascending order.
                                this.Sort(objLocalGroupingColumn, ListSortDirection.Ascending);
                            }

                            // If there are visible columns...
                            int intVisibleColumnsCount = this.Columns.GetColumnCount(DataGridViewElementStates.Visible);
                            if (intVisibleColumnsCount > 0)
                            {
                                DataGridViewRow objPreviousRow = null;
                                int intVisibleRowIndex = this.Rows.GetFirstRow(DataGridViewElementStates.None);

                                DataGridViewColumn objFirstVisubleColumn = this.Columns.GetFirstColumn(DataGridViewElementStates.Visible);
                                if (objFirstVisubleColumn != null)
                                {
                                    bool blnRemovePrevCellPanel = false;
                                    int intFirstColumnIndex = objFirstVisubleColumn.Index;

                                    if (mintPrevGroupHeaderCellPanelIndex >= 0 && intFirstColumnIndex != mintPrevGroupHeaderCellPanelIndex)
                                    {
                                        blnRemovePrevCellPanel = true;
                                    }

                                    // Iterate through the rows to hide rows with duplicate values in selected column, and to create group headers for distinct rows.
                                    while (intVisibleRowIndex >= 0)
                                    {
                                        // Get current row.
                                        DataGridViewRow objCurrentRow = this.Rows[intVisibleRowIndex];
                                        if (objCurrentRow != null)
                                        {
                                            // Remove previous group header cell panel.
                                            if (blnRemovePrevCellPanel)
                                            {
                                                objCurrentRow.Cells[mintPrevGroupHeaderCellPanelIndex].Panel = null;
                                            }

                                            // Get current value.
                                            object objCurrentValue = objCurrentRow.Cells[strColumnName].Value;

                                            // If it is not the 1st row, and a duplicate found..
                                            if (objPreviousRow != null && object.Equals(objPreviousRow.Cells[strColumnName].Value, objCurrentValue))
                                            {
                                                // Hide current row.
                                                if (objCurrentRow.Visible)
                                                {
                                                    objCurrentRow.Visible = false;
                                                }

                                                // Reset header cell panel for non-header rows.
                                                objCurrentRow.Cells[0].Rowspan = 0;
                                                objCurrentRow.Cells[0].Colspan = 0;
                                            }
                                            // If this is the 1st row, or is not a duplicate..
                                            else
                                            {
                                                if (this.SystemHierarchicInfos.Count > 0)
                                                {
                                                    if (!objCurrentRow.IsNewRow)
                                                    {
                                                        // Create Group header.
                                                        CreateGroupHeader(strColumnDataPropertyName, intFirstColumnIndex, intVisibleColumnsCount, objCurrentRow.Cells[strColumnName].Value, objCurrentRow);
                                                    }
                                                    else
                                                    {
                                                        // Create Group header for NewRow.
                                                        CreateGroupHeader("New Row", intFirstColumnIndex, intVisibleColumnsCount, "Empty", objCurrentRow);
                                                    }
                                                }

                                                // Update loop variables.                                               
                                                objPreviousRow = objCurrentRow;
                                            }

                                            // Get next visible row.
                                            intVisibleRowIndex = this.Rows.GetNextRow(intVisibleRowIndex, DataGridViewElementStates.None);
                                        }
                                    }

                                    // Set group header cell panel column index.
                                    mintPrevGroupHeaderCellPanelIndex = intFirstColumnIndex;
                                }
                            }
                        }
                        else
                        {
                            throw new Exception(SR.GetString("DataGridView_InvalidGroupingColumnName", new object[] { strColumnDataPropertyName }));
                        }
                    }
                }
            }

            SwitchPreRenderUpdate(~PreRenderUpdateType.GroupHeaders);
        }

        /// <summary>
        /// Creates the group header.
        /// </summary>
        /// <param name="strColumnDataPropertyName">Name of the STR column data property.</param>
        /// <param name="intFirstVisibleColumnIndex">Index of the int first visible column.</param>
        /// <param name="intVisibleColumnsCount">The int visible columns count.</param>
        /// <param name="objCurrentValue">The obj current value.</param>
        /// <param name="objCurrentRow">The obj current row.</param>
        private void CreateGroupHeader(string strColumnDataPropertyName, int intFirstVisibleColumnIndex, int intVisibleColumnsCount, object objCurrentValue, DataGridViewRow objCurrentRow)
        {
            // Validate row visibility.
            if (!objCurrentRow.Visible)
            {
                objCurrentRow.Visible = true;
            }

            BindingSource objRowBindingSource = null;

            // Use binding source for group items count, if supported.
            if (mblnSupportGroupCount && !objCurrentRow.IsNewRow)
            {
                objRowBindingSource = this.GetClonedBindingSourceWithFilterForNextLevel(objCurrentRow);
            }

            //Get 1st row cell.
            DataGridViewCell objFirstCell = objCurrentRow.Cells[intFirstVisibleColumnIndex];
            if (objFirstCell != null)
            {
                string strCurrentValue = string.Empty;

                if (objCurrentValue != null)
                {
                    // Get string value.
                    strCurrentValue = objCurrentValue.ToString();
                }

                // Raise GroupHeaderFormatting event to customize group header.
                FormatGroupHeader(objFirstCell, intVisibleColumnsCount, strColumnDataPropertyName, strCurrentValue, objRowBindingSource);
            }
        }

