        /// <summary>
        /// Fires the click events.
        /// </summary>
        /// <param name="objMouseEventArgs">The <see cref="Gizmox.WebGUI.Forms.MouseEventArgs"/> instance containing the event data.</param>
        /// <param name="objDataGridViewCellEventArgs">The <see cref="Gizmox.WebGUI.Forms.DataGridViewCellEventArgs"/> instance containing the event data.</param>
        /// <param name="objDataGridViewCellMouseEventArgs">The <see cref="Gizmox.WebGUI.Forms.DataGridViewCellMouseEventArgs"/> instance containing the event data.</param>
        internal void FireClickEvents(MouseEventArgs objMouseEventArgs, DataGridViewCellEventArgs objDataGridViewCellEventArgs, DataGridViewCellMouseEventArgs objDataGridViewCellMouseEventArgs)
        {
            // Check if click was executed through right button.
            bool blnIsRightClick = (objMouseEventArgs.Button == MouseButtons.Right);

            if (!blnIsRightClick)
            {
                this.OnCellContentClick(objDataGridViewCellEventArgs);
            }

            this.OnCellMouseDown(objDataGridViewCellMouseEventArgs);
            this.OnCellMouseUp(objDataGridViewCellMouseEventArgs);

            if (!blnIsRightClick)
            {
                this.OnCellClick(objDataGridViewCellEventArgs);
            }

            this.OnClick(objMouseEventArgs);
        }

        /// <summary>
        /// Fires the double click events.
        /// </summary>
        /// <param name="objDataGridViewCellEventArgs">The <see cref="Gizmox.WebGUI.Forms.DataGridViewCellEventArgs"/> instance containing the event data.</param>
        internal void FireDoubleClickEvents(DataGridViewCellEventArgs objDataGridViewCellEventArgs)
        {
            this.OnCellContentDoubleClick(objDataGridViewCellEventArgs);
            this.OnCellDoubleClick(objDataGridViewCellEventArgs);
            this.OnDoubleClick(EventArgs.Empty);

        }

        /// <summary>
        /// 
        /// </summary>
        /// <param name="objDataGridViewCell"></param>
        /// <param name="intColumnIndex"></param>
        /// <param name="intRowIndex"></param>
        internal void OnCellEnter(ref DataGridViewCell objDataGridViewCell, int intColumnIndex, int intRowIndex)
        {
            this.OnCellEnter(new DataGridViewCellEventArgs(intColumnIndex, intRowIndex));
            if (objDataGridViewCell != null)
            {
                if (this.IsInnerCellOutOfBounds(intColumnIndex, intRowIndex))
                {
                    objDataGridViewCell = null;
                }
                else
                {
                    objDataGridViewCell = this.Rows.SharedRow(intRowIndex).Cells[intColumnIndex];
                }
            }
        }

        /// <summary>
        /// Columns the editable.
        /// </summary>
        /// <param name="intColumnIndex">Index of the column.</param>
        /// <returns></returns>
        private bool ColumnEditable(int intColumnIndex)
        {
            if ((this.Columns[intColumnIndex].IsDataBound && (this.DataConnection != null)) && !this.DataConnection.AllowEdit)
            {
                return false;
            }
            return true;
        }

        /// <summary>
        /// Begins the edit internal.
        /// </summary>
        /// <param name="blnSelectAll">if set to <c>true</c> [BLN select all].</param>
        /// <returns></returns>
        private bool BeginEditInternal(bool blnSelectAll)
        {
            return BeginEditInternal(blnSelectAll, false);
        }

        /// <summary>
        /// Begins the edit internal.
        /// </summary>
        /// <param name="blnSelectAll">if set to <c>true</c> [select all].</param>
        /// <param name="blnClientSource">if set to <c>true</c> [BLN client source].</param>
        /// <returns></returns>
        private bool BeginEditInternal(bool blnSelectAll, bool blnClientSource)
        {
            bool blnFlag;
            Control objEditingControl = this.EditingControl;
            Control objLatestEditingControl = this.LatestEditingControl;

            if (this.mobjDataGridViewOper[0x200000])
            {
                throw new InvalidOperationException(SR.GetString("DataGridView_BeginEditNotReentrant"));
            }
            try
            {
                Type objEditType;
                DataGridViewCellStyle objDataGridViewCellStyle;
                this.mobjDataGridViewOper[0x200000] = true;
                DataGridViewCell objCurrentCellInternal = this.CurrentCellInternal;
                if (!this.IsSharedCellReadOnly(objCurrentCellInternal, mobjCurrentCellPoint.Y) && this.ColumnEditable(mobjCurrentCellPoint.X))
                {
                    objEditType = objCurrentCellInternal.EditType;
