        /// <summary>Raises the <see cref="E:Gizmox.WebGUI.Forms.DataGridView.RowHeightChanged"></see> event.</summary>
        /// <param name="e">A <see cref="T:Gizmox.WebGUI.Forms.DataGridViewRowEventArgs"></see> that contains the event data. </param>
        /// <exception cref="T:System.ArgumentException">The row indicated by the <see cref="P:Gizmox.WebGUI.Forms.DataGridViewRowEventArgs.Row"></see> property of e does not belong to this <see cref="T:Gizmox.WebGUI.Forms.DataGridView"></see> control.</exception>
        protected virtual void OnRowHeightChanged(DataGridViewRowEventArgs e)
        {
            // Check if the GridView should resize all rows
            if (this.EnforceEqualRowSize)
            {
                int intNewHeight = e.Row.ThicknessInternal;

                // Update all other rows
                foreach (DataGridViewRow objRow in this.Rows)
                {
                    if (objRow.ThicknessInternal != intNewHeight)
                    {
                        // Set the thickness without invoking the OnRowHeightChanged event
                        objRow.SetThicknessInternal(intNewHeight);
                    }
                }
            }

            // Raise event if needed
            DataGridViewRowEventHandler objDataGridViewRowEventHandler = this.GetHandler(EVENT_DATAGRIDVIEWROWHEIGHTCHANGED) as DataGridViewRowEventHandler;
            if (objDataGridViewRowEventHandler != null)
            {
                if (NeedToAdjustFillingColumns)
                {
                    ResetUIState(false, false);
                }
                objDataGridViewRowEventHandler(this, e);
            }
        }

