        /// <summary>Raises the <see cref="E:Gizmox.WebGUI.Forms.DataGridView.RowStateChanged"></see> event.</summary>
        /// <param name="e">A <see cref="T:Gizmox.WebGUI.Forms.DataGridViewRowStateChangedEventArgs"></see> that contains the event data. </param>
        /// <param name="intRowIndex">The index of the row that is changing state.</param>
        /// <exception cref="T:System.InvalidCastException">The row changed from read-only to read/write, enabling the current cell to enter edit mode, but the <see cref="P:Gizmox.WebGUI.Forms.DataGridViewCell.EditType"></see> property of the current cell does not indicate a class that derives from <see cref="T:Gizmox.WebGUI.Forms.Control"></see> and implements <see cref="T:Gizmox.WebGUI.Forms.IDataGridViewEditingControl"></see>.</exception>
        protected virtual void OnRowStateChanged(int intRowIndex, DataGridViewRowStateChangedEventArgs e)
        {
            // If row.Frozen changed, we need to update the vertical scroll bar
            // A hidden row may become visible and vice-versa, we'd better repaint the whole control
            DataGridViewRow objDataGridViewRow = e.Row;
            DataGridViewElementStates enmNewState = DataGridViewElementStates.None;

            bool blnRowVisible = false;

            // Get the Grid Rows
            DataGridViewRowCollection objRows = this.Rows;

            if (intRowIndex >= 0)
            {
                enmNewState = objRows.GetRowState(intRowIndex);
                blnRowVisible = ((enmNewState & DataGridViewElementStates.Visible) != 0);
            }
            switch (e.StateChanged)
            {
                // At this point we assume that only the Selected state has an influence on the rendering of the row. 
                // If there is a customer scenario where another state has an influence, the dev will have to invalidate the row by hand.
                // case DataGridViewElementStates.ReadOnly: 
                // case DataGridViewElementStates.Resizable: 

                case DataGridViewElementStates.Selected:
                    if (blnRowVisible && this.BulkPaintCount == 0)
                    {
                        InvalidateRowPrivate(intRowIndex);
                    }
                    break;

                case DataGridViewElementStates.Frozen:
                    if (blnRowVisible)
                    {
                        PerformLayoutPrivate(true);
                        Invalidate();
                    }
                    break;

                case DataGridViewElementStates.Visible:
                    {
                        if (!blnRowVisible && (enmNewState & DataGridViewElementStates.Displayed) != 0)
                        {
                            // Displayed row becomes invisible. Turns off the Displayed state. 
                            objRows.SetRowState(intRowIndex, DataGridViewElementStates.Displayed, false);
                        }

                        PerformLayoutPrivate(true);
                        Invalidate();

                        bool blnRowDisplayed = (objRows.GetRowState(intRowIndex) & DataGridViewElementStates.Displayed) != 0;
                        DataGridViewAutoSizeRowsMode enmAutoSizeRowsMode = this.AutoSizeRowsMode;
                        DataGridViewAutoSizeRowsModeInternal autoSizeRowsModeInternal = (DataGridViewAutoSizeRowsModeInternal)enmAutoSizeRowsMode;

                        bool blnAutoSizeRow = false;

                        if (autoSizeRowsModeInternal != DataGridViewAutoSizeRowsModeInternal.None)
                        {
                            int intHeight = objDataGridViewRow.ThicknessInternal;
                            if (blnRowVisible)
                            {
                                // Cache row's height before potential autosizing occurs
                                // Valid operation even for shared rows 
                                objDataGridViewRow.CachedThickness = intHeight;
                                if (!((autoSizeRowsModeInternal & DataGridViewAutoSizeRowsModeInternal.DisplayedRows) != 0 && !blnRowDisplayed))
                                {
                                    AutoResizeRowInternal(intRowIndex, MapAutoSizeRowsModeToRowMode(enmAutoSizeRowsMode), false /*fixedWidth*/, true /*internalAutosizing*/);
                                    blnAutoSizeRow = true;
                                }
                            }
                            else if (intHeight != objDataGridViewRow.CachedThickness)
                            {
                                // Rows that are made invisible in the collection take their non-autosized height 
                                // Not calling OnRowHeightInfoPushed(...) because rows are autosized
                                // Make sure the affected row is unshared 
                                if (objDataGridViewRow.Index == -1)
                                {
                                    objDataGridViewRow = objRows[intRowIndex];
                                }
                                objDataGridViewRow.ThicknessInternal = Math.Max(objDataGridViewRow.MinimumHeight, objDataGridViewRow.CachedThickness);
                            }
                        }

                        // Auto size columms also if needed 
                        DataGridViewAutoSizeColumnCriteriaInternal autoSizeColumnCriteriaFilter = DataGridViewAutoSizeColumnCriteriaInternal.AllRows;
                        if (blnRowDisplayed)
                        {
                            autoSizeColumnCriteriaFilter |= DataGridViewAutoSizeColumnCriteriaInternal.DisplayedRows;
                        }
                        if (blnRowVisible && objRows.GetRowCount(DataGridViewElementStates.Visible) > 1)
                        {
                            // Columns can only expand, and not collapse.
                            AdjustExpandingColumns(autoSizeColumnCriteriaFilter, intRowIndex);
                        }
                        else
                        {
                            AutoResizeAllVisibleColumnsInternal(autoSizeColumnCriteriaFilter, true /*fixedHeight*/);
                        }

                        if (blnAutoSizeRow)
                        {
                            // Second round of row autosizing 
                            AutoResizeRowInternal(intRowIndex, MapAutoSizeRowsModeToRowMode(enmAutoSizeRowsMode), true /*fixedWidth*/, true /*internalAutosizing*/);
                        }
                        break;
                    }
            }

            DataGridViewRowStateChangedEventHandler objEventHandler = this.RowStateChanged;
            if (objEventHandler != null)
            {
                objEventHandler(this, e);
            }

            if (e.StateChanged == DataGridViewElementStates.ReadOnly &&
                intRowIndex == mobjCurrentCellPoint.Y &&
                !this.mobjDataGridViewOper[DATAGRIDVIEWOPER_inReadOnlyChange])
            {
                if ((enmNewState & DataGridViewElementStates.ReadOnly) == 0 &&
                    !this.ReadOnly &&
                    !this.Columns[mobjCurrentCellPoint.X].ReadOnly &&
                    ColumnEditable(mobjCurrentCellPoint.X) &&
                    !this.IsCurrentCellInEditMode &&
                    (this.EditMode == DataGridViewEditMode.EditOnEnter ||
                    (this.EditMode != DataGridViewEditMode.EditProgrammatically && this.CurrentCellInternal.EditType == null)))
                {
                    // Current row becomes read/write. Enter editing mode. 
                    BeginEditInternal(true /*selectAll*/);
                }
            }

        }

