                    if (blnSelected)
                    {
                        this.RemoveIndividuallySelectedCellsInColumn(intColumnIndex);
                        this.Columns[intColumnIndex].SelectedInternal = true;
                        this.SelectedBandIndexes.Add(intColumnIndex);
                    }
                    else
                    {
                        this.Columns[intColumnIndex].SelectedInternal = false;
                        this.SelectedBandIndexes.Remove(intColumnIndex);
                    }
                }
                else if (!blnSelected)
                {
                    this.RemoveIndividuallySelectedCellsInColumn(intColumnIndex);
                }
            }
            finally
            {
                this.NoSelectionChangeCount--;
            }
        }

        /// <summary>
        /// Removes the individually selected cells in column.
        /// </summary>
        /// <param name="intColumnIndex">Index of the column.</param>
        private void RemoveIndividuallySelectedCellsInColumn(int intColumnIndex)
        {
            DataGridViewCell objCell;
            int num = 0;
            int num2 = 0;
            bool blnFlag = false;
            DataGridViewCellLinkedList objIndividualSelectedCells = this.IndividualSelectedCells;

            while (num < objIndividualSelectedCells.Count)
            {
                objCell = objIndividualSelectedCells[num];
                if (objCell.ColumnIndex == intColumnIndex)
                {
                    this.SetSelectedCellCore(objCell.ColumnIndex, objCell.RowIndex, false);
                    num2++;
                    if (num2 <= 8)
                    {
                        continue;
                    }
                    blnFlag = true;
                    break;
                }
                num++;
            }
            if (blnFlag)
            {
                this.BulkPaintCount++;
                try
                {
                    while (num < objIndividualSelectedCells.Count)
                    {
                        objCell = objIndividualSelectedCells[num];
                        if (objCell.ColumnIndex == intColumnIndex)
                        {
                            this.SetSelectedCellCore(objCell.ColumnIndex, objCell.RowIndex, false);
                        }
                        else
                        {
                            num++;
                        }
                    }
                }
                finally
                {
                    this.ExitBulkPaint(intColumnIndex, -1);
                }
            }
        }

        /// <summary>
        /// Sets the selected row core.
        /// </summary>
        /// <param name="intRowIndex">Index of the row.</param>
        /// <param name="blnSelected">if set to <c>true</c> [selected].</param>
        protected virtual void SetSelectedRowCore(int intRowIndex, bool blnSelected)
        {
            SetSelectedRowCore(intRowIndex, blnSelected, false);
        }

        private void SetSelectedRowCore(int intRowIndex, bool blnSelected, bool blnClientSource)
        {
            // Get the Grid Rows
            DataGridViewRowCollection objRows = this.Rows;

            if ((intRowIndex < 0) || (intRowIndex >= objRows.Count))
            {
                throw new ArgumentOutOfRangeException("rowIndex");
            }
            this.SelectionChangeCount++;
            try
            {
                if (((objRows.GetRowState(intRowIndex) & DataGridViewElementStates.Selected) != DataGridViewElementStates.None) != blnSelected)
                {
                    if (blnSelected)
                    {
                        this.RemoveIndividuallySelectedCellsInRow(intRowIndex, blnClientSource);
                        this.SelectedBandIndexes.Add(intRowIndex);
                        objRows.SetRowState(intRowIndex, DataGridViewElementStates.Selected, true);
                    }
                    else
                    {
                        this.SelectedBandIndexes.Remove(intRowIndex);

                        objRows.SetRowState(intRowIndex, DataGridViewElementStates.Selected, false);
                    }

                    if (!blnClientSource)
                    {
                        objRows[intRowIndex].UpdateParams(AttributeType.Visual);
                    }
                }
                else if (!blnSelected)
                {
                    this.RemoveIndividuallySelectedCellsInRow(intRowIndex, blnClientSource);
                }
            }
            finally
            {
                this.NoSelectionChangeCount--;
            }
        }

