        public ObservableCollection<HierarchicInfo> GetRelevantHierarchicInfos()
        {
            if (this.SystemHierarchicInfos.Count > 0)
            {
                return this.SystemHierarchicInfos;
            }

            return this.HierarchicInfos;
        }

