        /// <summary>
        /// Gets the cloned binding source with filter for next level.
        /// </summary>
        /// <param name="objRow">The obj row.</param>
        /// <returns></returns>
        internal BindingSource GetClonedBindingSourceWithFilterForNextLevel(DataGridViewRow objRow)
        {
            ObservableCollection<HierarchicInfo> arrHierarchicInfos = this.GetRelevantHierarchicInfos();
            if (arrHierarchicInfos.Count > 0)
            {
                // Get the next hierarchy level
                HierarchicInfo objNextInfoLevel = arrHierarchicInfos[0];

                // Duplicate the binding source
                BindingSource objClonedSource = CloneBindingSource(objNextInfoLevel);

                // Create the filer string
                string strFilter = GetFilterForRowChildGrid(objRow);
                if (!string.IsNullOrEmpty(strFilter))
                {
                    objClonedSource.Filter = strFilter;

                    return objClonedSource;
                }
            }

            return null;
        }

        /// <summary>
        /// Clones the binding source.
        /// </summary>
        /// <param name="objNextInfoLevel">The obj next info level.</param>
        /// <returns></returns>
        private static BindingSource CloneBindingSource(HierarchicInfo objNextInfoLevel)
        {
            // Take the root source
            BindingSource objClonedSource = (objNextInfoLevel.BindedSource as ICloneable).Clone() as BindingSource;

            // Get a reference to the last BindingSource object
            BindingSource objLastBindingSource = objClonedSource;

            // Take the DataSource as a BindingSource to check if it is also a BindingSource
            BindingSource objDataSource = objClonedSource.DataSource as BindingSource;

            // Loop while finding a data source which is a binding source.
            while (objDataSource != null)
            {
                objLastBindingSource = objDataSource;
                objDataSource = objDataSource.DataSource as BindingSource;
            }

            DataTable objDataTable = objLastBindingSource.DataSource as DataTable;
            if (objDataTable != null)
            {
                /*
                    Each DataTable has a single DataView, so filtering it will change any source that uses this DataTable, so we wrap it inside it's own DataView class to prevent it
                */
                objLastBindingSource.DataSource = new DataView(objDataTable);
            }

            return objClonedSource;
        }

        /// <summary>
        /// Gets the filter for row child grid.
        /// </summary>
        /// <param name="objRow">The obj row.</param>
        /// <returns></returns>
        internal string GetFilterForRowChildGrid(DataGridViewRow objRow)
        {
            ObservableCollection<HierarchicInfo> arrHierarchicInfos = this.GetRelevantHierarchicInfos();
            if (arrHierarchicInfos.Count > 0)
            {
                // Get the next hierarchy level
                HierarchicInfo objNextInfoLevel = arrHierarchicInfos[0];

                // Create the filter template if not yet created
                if (string.IsNullOrEmpty(this.mstrFilterTemplate))
                {
                    // Filter template for all child data sources
                    this.mstrFilterTemplate = GetFilterTemplate(objNextInfoLevel);
                }

                // Create the filer string
                return string.Format(this.mstrFilterTemplate, CreateRowFilterValueList(objRow, objNextInfoLevel.Keys));
            }

            return string.Empty;
        }

        /// <summary>
        /// Creates the row filter value list.
        /// </summary>
        /// <param name="objRow">The obj row.</param>
        /// <param name="objFilteringDataMembers">The obj filtering data members.</param>
        /// <returns></returns>
        private string[] CreateRowFilterValueList(DataGridViewRow objRow, IList<string> objFilteringDataMembers)
        {
            // Place holder index
            int i = 0;

            // Values array
            string[] arrValueList = new string[objFilteringDataMembers.Count];

            // Go through each filter member and extract its value from the row
            foreach (string strFilteringDataMember in objFilteringDataMembers)
            {
                // Check if we already know the real column's name
                if (!RealFilteringDataMemberIndexByProposedFilteringDataMember.ContainsKey(strFilteringDataMember))
                {
                    // If we don't have the real column's name, try to get it
                    CreateRealDataMemberForProposedMember(strFilteringDataMember);
                }

                // Get the actual value
                object objValue = objRow.Cells[RealFilteringDataMemberIndexByProposedFilteringDataMember[strFilteringDataMember]].Value;

                string strValue;

                // Allow null values to be filtered.
                if (objValue == null || objValue is DBNull)
                {
                    strValue = "IS NULL";
                }
                else
                {
                    // Strigify the value
                    strValue = objValue.ToString();

                    strValue = string.Format("= {0}", GetQueryComparisionValue(objValue.GetType(), strValue));
                }

                arrValueList[i++] = strValue;
            }

            return arrValueList;
        }

        /// <summary>
        /// Creates the real data member from the proposed member.
        /// </summary>
        /// <param name="strFilteringDataMember">The STR filtering data member.</param>
        private void CreateRealDataMemberForProposedMember(string strFilteringDataMember)
        {
            string strRealName = this.Columns.GetRealDataMemberForProposedMember(strFilteringDataMember);

            if (!string.IsNullOrEmpty(strRealName))
            {
                this.RealFilteringDataMemberIndexByProposedFilteringDataMember.Add(strFilteringDataMember, strRealName);
                return;
            }

            throw new Exception("The grid does not contain a columns with the given filter data member name: Given name - '" + strFilteringDataMember + "'");
        }

        /// <summary>
        /// Creates a template for the filter field
        /// </summary>
        /// <param name="objCurrentInfoLevel">The obj current info level.</param>
        /// <param name="objNextInfoLevel">The obj next info level.</param>
        /// <returns></returns>
        private string GetFilterTemplate(HierarchicInfo objNextInfoLevel)
        {
            // Index
            int i = 0;

            // And operator place holder
            string strAnd = string.Empty;

            StringBuilder objBuilder = new StringBuilder();

            // Iterate through all filters
            foreach (FilterRelation objFilterRelation in objNextInfoLevel.FilteringDataMembers)
            {
                // Build the filter string with place holders for the values
                objBuilder.Append(strAnd);
                objBuilder.Append("[");
                objBuilder.Append(objFilterRelation.TargetColumnDataName);
                objBuilder.Append("]");
                objBuilder.Append(" ");
                objBuilder.Append("{");
                objBuilder.Append(i++);
                objBuilder.Append("}");

                strAnd = " AND ";
            }

            return objBuilder.ToString();
        }

