        /// </summary>
        /// <param name="enmPreRenderUpdateType">The prerender update type.</param>
        /// <returns>
        ///   <c>true</c> if the specified prerender update type dirty; otherwise, <c>false</c>.
        /// </returns>
        private bool ShouldPreRenderUpdate(PreRenderUpdateType enmPreRenderUpdateType)
        {
            return (menmPreRenderUpdateTypes & enmPreRenderUpdateType) != PreRenderUpdateType.None;
        }

        /// <summary>
        /// Initializes the system hierarchic infos.
        /// </summary>
        private void InitializeSystemHierarchicInfos()
        {
            BindingSource objBindingSource = this.DataSource as BindingSource;
            if (objBindingSource != null)
            {
                // Reset system infos.
                this.SystemHierarchicInfos.Clear();

                for (int intGroupIndex = 0; intGroupIndex < this.GroupingColumns.Count; intGroupIndex++)
                {
                    // Create hierarchic info.
                    HierarchicInfo objHierarchicInfo = new HierarchicInfo();

                    // Set its binded source to be DGV's bindingSource
                    objHierarchicInfo.BindedSource = objBindingSource;

                    // Create filter relations for hierarchic infos, increasingly.
                    for (int intFilterIndex = 0; intFilterIndex <= intGroupIndex; intFilterIndex++)
                    {
                        FilterRelation objFilterRelation = new FilterRelation();
                        objFilterRelation.SourceColumnDataName = this.GroupingColumns[intFilterIndex];
                        objFilterRelation.TargetColumnDataName = this.GroupingColumns[intFilterIndex];

                        objHierarchicInfo.FilteringDataMembers.Add(objFilterRelation);
                    }

                    // Add new hierarchic info to system hierarchies collection.
                    this.SystemHierarchicInfos.Add(objHierarchicInfo);
                }
            }
        }


