        /// <summary>
        /// Initializes the filter row.
        /// </summary>
        private void InitializeFilterRow()
        {
            // Filtering could be performed on binding source only.
            BindingSource objBindingSource = this.DataSource as BindingSource;

            // Create DataGridViewFilterRow.
            if (mobjDataGridViewFilterRow == null)
            {
                mobjDataGridViewFilterRow = new DataGridViewFilterRow();
                mobjDataGridViewFilterRow.IndexInternal = 0;
                mobjDataGridViewFilterRow.Height = 24;
            }

            // Connect row to grid and header cell
            mobjDataGridViewFilterRow.DataGridViewInternal = null;
            mobjDataGridViewFilterRow.HeaderCell.DataGridViewInternal = this;

            // Preserve filters Enabled states
            List<string> arrNonFilteredColumns = new List<string>();

            if (mobjDataGridViewFilterRow.Cells != null)
            {
                // If has source to bind...
                if (objBindingSource != null)
                {
                    foreach (DataGridViewFilterCell objDataGridViewFilterCell in mobjDataGridViewFilterRow.Cells)
                    {
                        // Store filter-disabled cells
                        if (!objDataGridViewFilterCell.AllowRowFiltering)
                        {
                            arrNonFilteredColumns.Add(objDataGridViewFilterCell.DataPropertyName);
                        }
                    }
                }

                // Clear all cells.
                mobjDataGridViewFilterRow.Cells.Clear();
            }

            // Add new cells
            foreach (DataGridViewColumn objDataGridViewColumn in this.Columns)
            {
                // Restore filter Enabled states.
                if (arrNonFilteredColumns.Contains(objDataGridViewColumn.DataPropertyName))
                {
                    objDataGridViewColumn.AllowRowFilteringInternal = false;
                }

                // Create filter cell.
                DataGridViewFilterCell objDataGridViewFilterCell = new DataGridViewFilterCell(this, objDataGridViewColumn, objBindingSource != null);

                mobjDataGridViewFilterRow.Cells.Add(objDataGridViewFilterCell);

                // Register event, if filtering is ON.
                if (objBindingSource != null)
                {
                    objDataGridViewFilterCell.FilterChanged += new EventHandler(OnFilterCellChanged);
                }
            }

            // Connect row to grid.
            mobjDataGridViewFilterRow.DataGridViewInternal = this;
        }

