        /// <summary>
        /// Applies the data grid view filter.
        /// </summary>
        /// <param name="sender">The sender.</param>
        /// <param name="e">The <see cref="System.EventArgs"/> instance containing the event data.</param>
        internal void ApplyDataGridViewFilter()
        {
            // Get binding source.
