                // Apply filter.
                objBindingSource.Filter = ConstructFullFilterExpression();
            }
        }

        /// <summary>
        /// Constructs the full filter expression from every FilterRow cell and column header expressions.
        /// </summary>
        /// <returns></returns>
        internal string ConstructFullFilterExpression()
        {
            HierarchicDataGridView objHierarchicDataGridView = this as HierarchicDataGridView;

            // Get base filter expression.
            string strBindingSourceFilter = (objHierarchicDataGridView != null) ? objHierarchicDataGridView.ContainingRow.DataGridView.GetFilterForRowChildGrid(objHierarchicDataGridView.ContainingRow) : string.Empty;

            // Append filter row filter expression.
            if (mobjDataGridViewFilterRow != null)
            {
                // Loop on all filter cells
                foreach (DataGridViewFilterCell objDataGridViewFilterCell in mobjDataGridViewFilterRow.Cells)
                {
                    DataGridViewColumn objColumn = objDataGridViewFilterCell.OwningColumn;

                    // Get column's custom filter
                    string strCurrentFilter = objColumn.CustomFilterExpression;

                    // If custom filter is empty, try to get filter from filter cell
                    if (string.IsNullOrEmpty(strCurrentFilter))
                    {
                        strCurrentFilter = this.GetFilterStatement(objDataGridViewFilterCell.ComparisonOperator, objDataGridViewFilterCell.DataPropertyName, objDataGridViewFilterCell.ValueType, objDataGridViewFilterCell.ComparisionValue, objDataGridViewFilterCell.ComparisionItem);
                    }

                    // If current filter is still empty, try to get filter from header filter
                    if (string.IsNullOrEmpty(strCurrentFilter))
                    {
                        // Get header cell
                        DataGridViewColumnHeaderCell objHeaderCell = objColumn.HeaderCell;
                        if (objHeaderCell != null)
                        {
                            // Get filter statement of current column head
                            strCurrentFilter = this.GetFilterStatement(FilterComparisonOperator.Equals, objColumn.DataPropertyName, objColumn.ValueType, objHeaderCell.FilterComboBox.Text, objHeaderCell.FilterComboBox.SelectedItem);
                        }
                    }

                    // If filter is not empty, append it to binding source filter
                    if (!string.IsNullOrEmpty(strCurrentFilter))
                    {
                        if (!string.IsNullOrEmpty(strBindingSourceFilter))
                        {
                            strBindingSourceFilter = string.Format("{0} AND ", strBindingSourceFilter);
                        }

                        strBindingSourceFilter = string.Format("{0}{1}", strBindingSourceFilter, strCurrentFilter);
                    }
                }
            }
            else // Check filter on culumns and header filters
            {
                DataGridViewColumn objVisibleColumn = this.Columns.GetFirstColumn(DataGridViewElementStates.Visible);

                // Iterate through visible columns..
                while (objVisibleColumn != null)
                {
                    // Get column's custom filter
                    string strCurrentFilter = objVisibleColumn.CustomFilterExpression;

                    // If custom filter is empty, try to get filter from filter cell
                    if (string.IsNullOrEmpty(strCurrentFilter))
                    {
                        // Append column header filters expression.
                        if (objVisibleColumn.HeaderCell != null && objVisibleColumn.ShowHeaderFilter)
                        {
                            // Get header cell
                            DataGridViewColumnHeaderCell objHeaderCell = objVisibleColumn.HeaderCell;

                            // Validate headercell; CustomFilter already handeled.
                            if (objHeaderCell != null && string.IsNullOrEmpty(objVisibleColumn.CustomFilterExpression))
                            {
                                // Get filter statement of current column head
                                strCurrentFilter = this.GetFilterStatement(FilterComparisonOperator.Equals, objVisibleColumn.DataPropertyName, objVisibleColumn.ValueType, objHeaderCell.FilterComboBox.Text, objHeaderCell.FilterComboBox.SelectedItem);
                            }
                        }
                    }

                    // If filter is not empty, append it to binding source filter
                    if (!string.IsNullOrEmpty(strCurrentFilter))
                    {
                        if (!string.IsNullOrEmpty(strBindingSourceFilter))
                        {
                            strBindingSourceFilter = string.Format("{0} AND ", strBindingSourceFilter);
                        }

                        strBindingSourceFilter = string.Format("{0}{1}", strBindingSourceFilter, strCurrentFilter);
                    }

                    // Get next visible column
                    objVisibleColumn = this.Columns.GetNextColumn(objVisibleColumn, DataGridViewElementStates.Visible, DataGridViewElementStates.None);
                }
            }
            return strBindingSourceFilter;
        }

        /// <summary>
        /// Gets the filter statement according to operator.
        /// </summary>
        /// <param name="enmComparisionOperator">The comparision operator.</param>
        /// <param name="strDataPropertyName">Name of the data property.</param>
        /// <param name="objComparisionValueType">Type of the value.</param>
        /// <param name="strComparisionValue">The comparision value.</param>
        /// <returns></returns>
        private string GetFilterStatement(FilterComparisonOperator enmComparisionOperator, string strDataPropertyName, Type objComparisionValueType, string strComparisionValue, object objComparisionItem)
        {
            string strFilterStatement = null;

            if (!string.IsNullOrEmpty(strDataPropertyName) && !string.IsNullOrEmpty(strComparisionValue) && objComparisionValueType != null)
            {
                // Else, check whether system filter applied.
                strFilterStatement = this.GetSystemFilterStatement(strDataPropertyName, objComparisionItem);

                // If non-system filter applied, construct filter expression.
                if (strFilterStatement == null)
                {
                    switch (enmComparisionOperator)
                    {
                        case FilterComparisonOperator.Equals:
                            strFilterStatement = string.Format("[{0}]={1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, strComparisionValue));
                            break;
                        case FilterComparisonOperator.NotEquals:
                            strFilterStatement = string.Format("[{0}]<>{1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, strComparisionValue));
                            break;
                        case FilterComparisonOperator.GreaterThan:
                            strFilterStatement = string.Format("[{0}]>{1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, strComparisionValue));
                            break;
                        case FilterComparisonOperator.GreaterThanOrEqualTo:
                            strFilterStatement = string.Format("[{0}]>={1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, strComparisionValue));
                            break;
                        case FilterComparisonOperator.LessThan:
                            strFilterStatement = string.Format("[{0}]<{1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, strComparisionValue));
                            break;
                        case FilterComparisonOperator.LessThanOrEqualTo:
                            strFilterStatement = string.Format("[{0}]<={1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, strComparisionValue));
                            break;
                        case FilterComparisonOperator.StartsWith:
                            strFilterStatement = string.Format("[{0}] LIKE {1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, string.Format("{0}%", strComparisionValue)));
                            break;
                        case FilterComparisonOperator.Like:
                        case FilterComparisonOperator.Contains:
                            strFilterStatement = string.Format("[{0}] LIKE {1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, string.Format("%{0}%", strComparisionValue)));
                            break;
                        case FilterComparisonOperator.EndsWith:
                            strFilterStatement = string.Format("[{0}] LIKE {1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, string.Format("%{0}", strComparisionValue)));
                            break;
                        case FilterComparisonOperator.DoesNotStartWith:
                            strFilterStatement = string.Format("[{0}] NOT LIKE {1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, string.Format("{0}%", strComparisionValue)));
                            break;
                        case FilterComparisonOperator.DoesNotEndWith:
                            strFilterStatement = string.Format("[{0}] NOT LIKE {1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, string.Format("%{0}", strComparisionValue)));
                            break;
                        case FilterComparisonOperator.NotLike:
                        case FilterComparisonOperator.DoesNotContain:
                            strFilterStatement = string.Format("[{0}] NOT LIKE {1}", strDataPropertyName, this.GetQueryComparisionValue(objComparisionValueType, string.Format("%{0}%", strComparisionValue)));
                            break;
                        default:
                            strFilterStatement = string.Empty;
                            break;
                    }
                }
            }

            return strFilterStatement;
        }

        /// <summary>
        /// Gets the system filter statement.
        /// </summary>
        /// <param name="strDataPropertyName">Name of the STR data property.</param>
        /// <param name="strComparisionValue">The STR comparision value.</param>
        /// <returns></returns>
        private string GetSystemFilterStatement(string strDataPropertyName, object objComparisionItem)
        {
            DataGridViewSystemFilterOption objOption = objComparisionItem as DataGridViewSystemFilterOption;
            if (objOption != null)
            {
                // All values.
                if (objOption.Option == SystemFilterOptions.All)
                {
                    return string.Empty;
                }

                // Only blank values.
                if (objOption.Option == SystemFilterOptions.Blanks)
                {
                    return string.Format("[{0}] IS NULL", strDataPropertyName);
                }

                // Only non-blank values.
                if (objOption.Option == SystemFilterOptions.NonBlanks)
                {
                    return string.Format("[{0}] IS NOT NULL", strDataPropertyName);
                }
            }

            return null;
        }

