        /// <summary>
        /// Gets the query comparision value according to its type.
        /// </summary>
        /// <param name="objComparisionValueType">Type of the comparision value.</param>
        /// <param name="strComparisionValue">The STR comparision value.</param>
        /// <returns></returns>
        protected virtual string GetQueryComparisionValue(Type objComparisionValueType, string strComparisionValue)
        {
            if (strComparisionValue != null)
            {
                // Escape "'"
                strComparisionValue = strComparisionValue.Replace("'", "''");

                if (objComparisionValueType == typeof(DateTime))
                {
                    DateTime dValue;
                    try
                    {
                        // datetime is formatted according to UI culture on input, UNC format on filterexpr.
                        dValue = Convert.ToDateTime(strComparisionValue, VWGContext.Current.CurrentUICulture);
                        strComparisionValue = string.Format("'{0}'", dValue.ToString(VWGContext.Current.CurrentUICulture.DateTimeFormat.UniversalSortableDateTimePattern));
                    }
                    catch (Exception)
                    {
                        strComparisionValue = string.Format("#{0}#", strComparisionValue);
                    }
                }
                else if (objComparisionValueType == typeof(decimal) ||
                    objComparisionValueType == typeof(float) ||
                    objComparisionValueType == typeof(double))
                {
                    double dValue;
                    try
                    {
                        // decimal numbers are formatted according to UI culture on input, need invariant culture on filterexpr.
                        dValue = Convert.ToDouble(strComparisionValue, VWGContext.Current.CurrentUICulture);
                        strComparisionValue = string.Format("{0}", dValue.ToString(CultureInfo.InvariantCulture));
                    }
                    catch (Exception)
                    {
                        strComparisionValue = string.Format("{0}", strComparisionValue);
                    }
                }
                else if (objComparisionValueType != typeof(sbyte) &&
                    objComparisionValueType != typeof(short) &&
                    objComparisionValueType != typeof(int) &&
                    objComparisionValueType != typeof(long) &&
                    objComparisionValueType != typeof(byte) &&
                    objComparisionValueType != typeof(ushort) &&
                    objComparisionValueType != typeof(uint) &&
                    objComparisionValueType != typeof(long) &&
                    objComparisionValueType != typeof(bool) &&
                    objComparisionValueType != typeof(char))
                {
                    strComparisionValue = string.Format("'{0}'", strComparisionValue);
                }

                else if (objComparisionValueType == typeof(bool))
                {
                    strComparisionValue = string.Format("{0}", (strComparisionValue.ToLower() == "true" ? "1" : "0"));
                }

            }

            return strComparisionValue;
        }

