            }
            float flt = (this.Columns.GetColumnsFillWeight(DataGridViewElementStates.None) - objDataGridViewColumn.FillWeight) + fillWeight;
            if (flt > 65535f)
            {
                object[] arrArgs = new object[] { 0xffff.ToString(CultureInfo.CurrentCulture) };
                throw new InvalidOperationException(SR.GetString("DataGridView_WeightSumCannotExceedLongMaxValue", arrArgs));
            }
        }

