        /// <summary>
        /// Sets the current cell.
        /// </summary>
        /// <param name="objValue">The obj value.</param>
        /// <param name="blnClientSource">if set to <c>true</c> [BLN client source].</param>
        internal void SetCurrentCell(DataGridViewCell objValue, bool blnClientSource)
        {
            if (((objValue != null) && ((objValue.RowIndex != mobjCurrentCellPoint.Y) || (objValue.ColumnIndex != mobjCurrentCellPoint.X))) || ((objValue == null) && (mobjCurrentCellPoint.X != -1)))
            {
                if (objValue == null)
                {
                    this.ClearSelection();
                    if (!this.SetCurrentCellAddressCore(-1, -1, true, true, false))
                    {
                        throw new InvalidOperationException(SR.GetString("DataGridView_CellChangeCannotBeCommittedOrAborted"));
                    }
                }
                else
                {
                    if (objValue.DataGridView != this)
                    {
                        throw new ArgumentException(SR.GetString("DataGridView_CellDoesNotBelongToDataGridView"));
                    }
                    if (!this.Columns[objValue.ColumnIndex].Visible || ((this.Rows.GetRowState(objValue.RowIndex) & DataGridViewElementStates.Visible) == DataGridViewElementStates.None))
                    {
                        throw new InvalidOperationException(SR.GetString("DataGridView_CurrentCellCannotBeInvisible"));
                    }
                    if (!this.IsInnerCellOutOfBounds(objValue.ColumnIndex, objValue.RowIndex))
                    {
                        this.ClearSelection(objValue.ColumnIndex, objValue.RowIndex, true, blnClientSource);
                        if (!this.SetCurrentCellAddressCore(objValue.ColumnIndex, objValue.RowIndex, true, false, false, blnClientSource))
                        {
                            throw new InvalidOperationException(SR.GetString("DataGridView_CellChangeCannotBeCommittedOrAborted"));
                        }
                    }

                    if (!blnClientSource)
                    {
                        this.PerformScrollIntoView(objValue, false);

                        //checking if the grid has paging set, and setting current page accordingly.
                        if (this.UseInternalPaging)
                        {
                            this.CurrentPage = GetCellPageNumber(objValue);
                        }
                    }
                }

                if (!blnClientSource)
                {
                    this.UpdateParams(AttributeType.Visual);
                }
            }
        }

        /// <summary>
        /// Scrolls cell into view.
        /// </summary>
        /// <param name="objDataGridViewCell">The data grid view cell.</param>
        public virtual void ScrollIntoView(DataGridViewCell objDataGridViewCell)
        {
            if (objDataGridViewCell != null && objDataGridViewCell.DataGridView != null && objDataGridViewCell.DataGridView == this)
            {
                if (this.UseInternalPaging)
                {
                    int intCurrentPage = (objDataGridViewCell.RowIndex / this.ItemsPerPage) + 1;
                    if (intCurrentPage > 0 && intCurrentPage <= this.TotalPages)
                        this.CurrentPage = intCurrentPage;
                }
                this.PerformScrollIntoView(objDataGridViewCell, false);
            }
        }

        /// <summary>
        /// Performs scroll into view.
        /// </summary>
        /// <param name="objDataGridViewCell">The data grid view cell.</param>
        /// <param name="blnHidePopups">if set to <c>true</c> [BLN hide popups].</param>
        internal void PerformScrollIntoView(DataGridViewCell objDataGridViewCell, bool blnHidePopups)
        {
            if (objDataGridViewCell != null)
            {
                // Invoke scroll into view for the recieved cell.
                IContextMethodInvoker objContextMethodInvoker = this.Context as IContextMethodInvoker;
                if (objContextMethodInvoker != null)
                {
                    objContextMethodInvoker.InvokeMethod(this, InvokationUniqueness.Component, "DataGridView_PerformScrollIntoView", this.ID, objDataGridViewCell.MemberIDInternal.ToString(), blnHidePopups ? "1" : "0");
                }
            }
        }

        /// <summary>
        /// Gets the cell page number.
        /// </summary>
        /// <param name="objDataGridViewCell">The obj data grid view cell.</param>
        /// <returns></returns>
        private int GetCellPageNumber(DataGridViewCell objDataGridViewCell)
        {
            // Returns the page of the cell (the pages list are 1-based so we add 1 to the page)
            return (objDataGridViewCell.RowIndex / this.ItemsPerPage) + 1;
        }

        /// <summary>
        /// Gets the paged rows.
        /// </summary>
        /// <param name="blnPageContainsFrozenRows">if set to <c>true</c> [BLN page contains frozen rows].</param>
        /// <returns></returns>
        private IList GetPagedRows(out bool blnPageContainsFrozenRows)
        {
            // Initizlize the contains frozen rows switch.
            blnPageContainsFrozenRows = false;

            // Get the Grid Rows
            DataGridViewRowCollection objGridRows = this.Rows;

            if (this.UseInternalPaging)
            {
                // Create a new rows list.
                List<DataGridViewRow> objRowsList = new List<DataGridViewRow>();

                // Calculate an index to start paging from.
                int intFromIndex = (this.CurrentPage - 1) * this.ItemsPerPage;

                // Define a rows index.
                int intRowsIndex = 0;

                // Define an index for visible rows.
                int intVisibleRowsIndex = -1;

                // Get rows count.
                int intRowsCount = objGridRows.Count;

                // Loops while rows list has not filled page.
                while (intRowsIndex < intRowsCount && objRowsList.Count < this.ItemsPerPage)
                {
                    // Check if current row is visible.
                    if (objGridRows[intRowsIndex].Visible)
                    {
                        // Raise the visible rows index.
                        intVisibleRowsIndex++;

                        // Check if the visible rows index is valid.
                        if (intVisibleRowsIndex >= intFromIndex)
                        {
                            // Get a reference to current row.
                            DataGridViewRow objDataGridViewRow = objGridRows[intRowsIndex];
                            if (objDataGridViewRow != null)
                            {
                                // Check if current row is frozen.
                                if (objDataGridViewRow.Frozen)
                                {
                                    // Flag that page contains frozen rows.
                                    blnPageContainsFrozenRows = true;
                                }

                                // Add current row.
                                objRowsList.Add(objDataGridViewRow);
                            }
                        }
                    }

                    // Raise the rows index.
                    intRowsIndex++;
                }

                return objRowsList;
            }

            return objGridRows;
        }

        /// <summary>
        /// Determines whether [is inner cell out of bounds] [the specified column index].
        /// </summary>
        /// <param name="intColumnIndex">Index of the column.</param>
        /// <param name="intRowIndex">Index of the row.</param>
        /// <returns>
        /// 	<c>true</c> if [is inner cell out of bounds] [the specified column index]; otherwise, <c>false</c>.
        /// </returns>
        private bool IsInnerCellOutOfBounds(int intColumnIndex, int intRowIndex)
        {
            if (((intColumnIndex < this.Columns.Count) && (intRowIndex < this.Rows.Count)) && (intColumnIndex != -1))
            {
                return (intRowIndex == -1);
            }
            return true;
        }

