        /// </value>
        internal bool NeedToAdjustFillingColumns
        {
            get
            {
                bool blnDataGridViewAutoSizeColumnsModeFill = this.AutoSizeColumnsMode == DataGridViewAutoSizeColumnsMode.Fill;

                foreach (DataGridViewColumn objColumn in this.Columns)
                {
                    if (objColumn.AutoSizeMode == DataGridViewAutoSizeColumnMode.Fill || (blnDataGridViewAutoSizeColumnsModeFill && objColumn.AutoSizeMode == DataGridViewAutoSizeColumnMode.NotSet))
                    {
                        return true;
                    }
                }

                return false;
            }
        }

