        [System.ComponentModel.DefaultValue(1)]
        public int TotalPages
        {
            get
            {
                // If is using internal paging.
                if (!this.UseInternalPaging)
                {
                    return this.TotalPagesInternal;
                }
                else
                {
                    // Get total visible items
                    double dblTotalVisibleItems = (double)this.TotalVisibleItems;

                    // If there is no rows return total pages = 1
                    if (dblTotalVisibleItems == 0)
                    {
                        return 1;
                    }
                    else
                    {
                        // Calculate total pages.
                        return Convert.ToInt32((int)Math.Ceiling(dblTotalVisibleItems / (double)this.ItemsPerPage));
                    }
                }
            }
            set
            {
                // If is using internal paging
                if (!this.UseInternalPaging)
                {
                    // If is in valid range
