        /// <value>The total visible rows.</value>
        private int TotalVisibleItems
        {
            get
            {
                // Get visible row count
                int intRowCount = this.Rows.GetRowCount(DataGridViewElementStates.Visible);

                // Check if row count is greater then zero.
                if (intRowCount > 0)
                {
                    // Check if new row is visible.
                    if (this.IsNewRowVisible())
                    {
                        // Remove the new row from items count
                        intRowCount--;
                    }
                }

                return intRowCount;

            }
        }

