        /// <summary>
        /// Add or remove hierarchic infos events.
        /// </summary>
        /// <param name="blnIsAdd">if set to <c>true</c> [BLN is add].</param>
        private void AddRemoveHierarchicInfosEvents(bool blnIsAdd)
        {
            if (blnIsAdd)
            {
                // Listen to the Hierarchic info change in order to re-bind the grid
                this.mobjHierarchicInfos.CollectionChanged += new NotifyCollectionChangedEventHandler(mobjHierarchicInfos_CollectionChanged);

                if (this.mobjHierarchicInfos.Count > 0)
                {
                    this.mobjHierarchicInfos[0].PropertyChanged += new PropertyChangedEventHandler(objHierarchicInfo_PropertyChanged);
                }
            }
            else
            {
                this.mobjHierarchicInfos.CollectionChanged -= new NotifyCollectionChangedEventHandler(mobjHierarchicInfos_CollectionChanged);

                if (this.mobjHierarchicInfos.Count > 0)
                {
                    this.mobjHierarchicInfos[0].PropertyChanged -= new PropertyChangedEventHandler(objHierarchicInfo_PropertyChanged);
                }
            }
        }

        /// <summary>
        /// Handles the PropertyChanged event of the objHierarchicInfo control.
        /// </summary>
        /// <param name="sender">The source of the event.</param>
        /// <param name="e">The <see cref="System.ComponentModel.PropertyChangedEventArgs"/> instance containing the event data.</param>
        void objHierarchicInfo_PropertyChanged(object sender, PropertyChangedEventArgs e)
        {
            // Reset bindings
            ResetDataBinding();
        }

        /// <summary>
        /// Handles the CollectionChanged event of the mobjHierarchicInfos control.
        /// </summary>
        /// <param name="sender">The source of the event.</param>
        /// <param name="e">The <see cref="System.Collections.Specialized.NotifyCollectionChangedEventArgs"/> instance containing the event data.</param>
        void mobjHierarchicInfos_CollectionChanged(object sender, NotifyCollectionChangedEventArgs e)
        {
            // Handle collection changed type
            switch (e.Action)
            {
                case NotifyCollectionChangedAction.Add:

                    // Check if first time adding  hierarchic
                    if (this.mobjHierarchicInfos.Count == e.NewItems.Count)
                    {
                        // Loop on all columns and check non of them is frozen
                        foreach (DataGridViewColumn objColumn in this.Columns)
                        {
                            if (objColumn.Frozen)
                            {
                                throw new Exception("DataGridView does not support hierarchies with frozen columns");
                            }
                        }
                    }

                    // Listen to any of the HierarchicInfo's property change order to re-bing the grid
                    foreach (HierarchicInfo objInfo in e.NewItems)
                    {
                        if (e.NewStartingIndex == 0)
                        {
                            objInfo.PropertyChanged += new PropertyChangedEventHandler(objHierarchicInfo_PropertyChanged);
                        }
                    }
                    break;
                case NotifyCollectionChangedAction.Remove:
                    // Remove listeners from removed items
                    foreach (HierarchicInfo objInfo in e.OldItems)
                    {
                        if (e.OldStartingIndex == 0)
                        {
                            objInfo.PropertyChanged -= new PropertyChangedEventHandler(objHierarchicInfo_PropertyChanged);
                        }
                    }
                    break;
                case NotifyCollectionChangedAction.Move:
                case NotifyCollectionChangedAction.Replace:
                case NotifyCollectionChangedAction.Reset:
                    break;
                default:
                    break;
            }

            // Reset the bindings
            ResetDataBinding();
        }

        /// <summary>
        /// Resets the data binding.
        /// </summary>
        internal void ResetDataBinding()
        {
            // Check that we are not suspended
            if (!this.IsLayoutSuspended)
            {
                // Clear the filter template because it may have been changed
                this.mstrFilterTemplate = null;

                // Data members may have been changed
                this.mobjRealFilteringDataMemberIndexByProposedFilteringDataMember = null;

                // Reset the data source
                if (this.DataSource != null && this.DataSource is BindingSource)
                {
                    (this.DataSource as BindingSource).ResetBindings(true);
                }

                // Initializes the system hierarchic infos.
                InitializeSystemHierarchicInfos();
            }
        }

        /// <summary>Gets or sets the default style applied to the row cells of the <see cref="T:Gizmox.WebGUI.Forms.DataGridView"></see>.</summary>
        /// <returns>The <see cref="T:Gizmox.WebGUI.Forms.DataGridViewCellStyle"></see> to apply to the row cells of the <see cref="T:Gizmox.WebGUI.Forms.DataGridView"></see>.</returns>
        /// <filterpriority>1</filterpriority>
        [SRCategory("CatAppearance"), SRDescription("DataGridView_RowsDefaultCellStyleDescr")]
        public DataGridViewCellStyle RowsDefaultCellStyle
        {
            get
            {
                if (mobjRowsDefaultCellStyle == null)
                {
                    mobjRowsDefaultCellStyle = new DataGridViewCellStyle();
                    mobjRowsDefaultCellStyle.AddScope(this, DataGridViewCellStyleScopes.Rows);
                }

                return this.mobjRowsDefaultCellStyle;
            }
            set
            {
                mobjRowsDefaultCellStyle = this.RowsDefaultCellStyle;
                mobjRowsDefaultCellStyle.RemoveScope(DataGridViewCellStyleScopes.Rows);

                mobjRowsDefaultCellStyle = value;
                if (value != null)
                {
                    mobjRowsDefaultCellStyle.AddScope(this, DataGridViewCellStyleScopes.Rows);
                }

                DataGridViewCellStyleDifferences differencesFrom = mobjRowsDefaultCellStyle.GetDifferencesFrom(this.RowsDefaultCellStyle);
                if (differencesFrom != DataGridViewCellStyleDifferences.None)
                {
                    this.CellStyleChangedEventArgs.ChangeAffectsPreferredSize = differencesFrom == DataGridViewCellStyleDifferences.AffectPreferredSize;
                    this.OnRowsDefaultCellStyleChanged(this.CellStyleChangedEventArgs);
                }
            }
        }

