                    {
                        // Initialize block height.
                        int intBlockHeight = 0;

                        // Loop all block's rows.
                        foreach (DataGridViewRow objDataGridViewRow in this)
                        {
                            // Check if current row is not frozen.
                            if (!objDataGridViewRow.Frozen)
