            public bool ContainsFrozenRows
            {
                get
                {
                    return mblnContainsFrozenRows;
                }
            }

            #endregion Properties

            #region Methods

            /// <summary>
            /// Renders the row block
            /// </summary>
            /// <param name="objContext">The context.</param>
            /// <param name="objWriter">The writer.</param>
            /// <param name="lngRequestID">The request ID.</param>
            /// <param name="blnRenderOwner">if set to <c>true</c> [BLN render owner].</param>
            /// <param name="blnFullRender">if set to <c>true</c> [BLN full render].</param>
            /// <param name="intTopPosition">The block's top position.</param>
            /// <param name="intGridScrollTop">The grid scroll top.</param>
            /// <param name="intGridHeight">Height of the grid.</param>
            public void RenderBlock(IContext objContext, IResponseWriter objWriter, long lngRequestID, bool blnRenderOwner, bool blnFullRender, int intTopPosition, int intGridScrollTop, int intGridHeight)
            {
                // Get the block info
                DataGridRowBlockInfo objBlockInfo = this.BlockInfo;
                if (objBlockInfo != null)
                {
                    // Get block height.
                    int intBlockHeight = this.BlockHeight;

                    // Calculate block's bottom position.
                    int intBottomPosition = (intTopPosition + intBlockHeight);

                    // Calculate grid's bottom position.
                    int intGridBottomPosition = (intGridScrollTop + intGridHeight);

                    // Get a flag indicating if block is dirty
                    bool blnIsDirtyBlock = objBlockInfo.IsDirty(lngRequestID);

                    // Check if block should render its rows.
                    bool blnShouldRenderRows = objBlockInfo.IsLoaded || this.ContainsFrozenRows;

                    // In case of full rendering and rows should not be rendered.
                    if (blnFullRender && !blnShouldRenderRows)
                    {
                        // Check if the top part of the block is visible.
                        if (intTopPosition >= intGridScrollTop && intTopPosition < intGridBottomPosition)
                        {
                            blnShouldRenderRows = true;
                        }
                        // Check if the bottom part of the block is visible.
                        else if (intBottomPosition > intGridScrollTop && intBottomPosition <= intGridBottomPosition)
                        {
                            blnShouldRenderRows = true;
                        }
                        // Check if the block spreads over the whole scrolling area.
                        else if (intTopPosition <= intGridScrollTop && intBottomPosition >= intGridBottomPosition)
                        {
                            blnShouldRenderRows = true;
                        }

                        // In case that current block should be visible on full render.
                        if (blnShouldRenderRows)
                        {
                            // Load rows.
                            objBlockInfo.LoadRows();
                        }
                    }

                    // If is full render or dirty
                    if (blnFullRender || blnIsDirtyBlock)
                    {
                        objWriter.WriteStartElement(WGConst.Prefix, WGTags.DataGridViewBlock, WGConst.Namespace);
                        objWriter.WriteAttributeString(WGAttributes.MemberID, string.Format("{0}{1}", WGTags.DataGridViewBlock, this.mintBlockId.ToString()));
                        objWriter.WriteAttributeString(WGAttributes.OwnerID, mobjDataGrid.ID.ToString());
                        objWriter.WriteAttributeString(WGAttributes.Height, intBlockHeight.ToString());
                        objWriter.WriteAttributeString(WGAttributes.Loaded, blnShouldRenderRows ? "1" : "0");

                        // Check if block should render its rows.
                        if (blnShouldRenderRows)
                        {
                            objWriter.WriteAttributeString(WGAttributes.Visible, "1");

                            //  Render the block's rows.
                            RenderBlockRows(objContext, objWriter, lngRequestID, blnRenderOwner, blnIsDirtyBlock);
                        }

                        objWriter.WriteEndElement();
                    }
                    else
                    {
                        //  Render the block's rows.
                        RenderBlockRows(objContext, objWriter, lngRequestID, blnRenderOwner, blnIsDirtyBlock);
                    }
                }
            }

            /// <summary>
            ///  Render the block's rows.
            /// </summary>
            /// <param name="objContext"></param>
            /// <param name="objWriter"></param>
            /// <param name="lngRequestID"></param>
            /// <param name="blnRenderOwner"></param>
            /// <param name="blnIsDirtyBlock"></param>
            private void RenderBlockRows(IContext objContext, IResponseWriter objWriter, long lngRequestID, bool blnRenderOwner, bool blnIsDirtyBlock)
            {
                // Loop all paged rows.
                foreach (DataGridViewRow objDataGridViewRow in this)
                {
                    // Render current row.
                    ((IRenderableComponentMember)objDataGridViewRow).RenderComponent(objContext, objWriter, blnIsDirtyBlock ? 0 : lngRequestID, blnRenderOwner);
                }
            }

            #endregion Methods


