        /// <summary>
        /// Opens the custom filter dialog.
        /// </summary>
        /// <param name="objDataGridViewCell">The obj data grid view cell.</param>
        internal void OpenCustomFilterDialog(DataGridViewCell objDataGridViewCell)
        {
            DataGridViewCustomFilterDialog objCustomFilterDialog = new DataGridViewCustomFilterDialog(objDataGridViewCell);
            objCustomFilterDialog.Closed += new EventHandler(objCustomFilterDialog_Closed);
            objCustomFilterDialog.ShowDialog();
        }

        /// <summary>
        /// Handles the Closed event of the objCustomFilterDialog control.
        /// </summary>
        /// <param name="sender">The source of the event.</param>
        /// <param name="e">The <see cref="System.EventArgs"/> instance containing the event data.</param>
        private void objCustomFilterDialog_Closed(object sender, EventArgs e)
        {
            DataGridViewCustomFilterDialog objCustomFilterDialog = sender as DataGridViewCustomFilterDialog;
            if (objCustomFilterDialog != null)
            {
                // If user pressed OK button
                if (objCustomFilterDialog.DialogResult == DialogResult.OK)
                {
                    // Get datagridview column from custom filter dialog
                    DataGridViewColumn objDataGridViewColumn = objCustomFilterDialog.Column;

                    // Get First filter statement
                    string strFilterA = this.GetFilterStatement(objCustomFilterDialog.OperatorA, objDataGridViewColumn.DataPropertyName, objDataGridViewColumn.ValueType, objCustomFilterDialog.ValueA, null);
                    string strFilterB = string.Empty;

                    // Check if secound filter should be applied 
                    if (objCustomFilterDialog.OperatorB != FilterComparisonOperator.None && objCustomFilterDialog.ValueB != string.Empty)
                    {
                        // Get secound filter statement
                        strFilterB = this.GetFilterStatement(objCustomFilterDialog.OperatorB, objDataGridViewColumn.DataPropertyName, objDataGridViewColumn.ValueType, objCustomFilterDialog.ValueB, null);
                    }

                    // Update column's CustomFilterExpression
                    if (strFilterB != string.Empty)
                    {
                        objDataGridViewColumn.CustomFilterExpression = string.Format("(({0}) {1} ({2}))", strFilterA, objCustomFilterDialog.FiltersRelation, strFilterB);
                    }
                    else
                    {
                        objDataGridViewColumn.CustomFilterExpression = string.Format("({0})", strFilterA);
                    }
                }
                else
                {
                    DataGridViewColumnHeaderCell objHeaderCell = objCustomFilterDialog.Cell as DataGridViewColumnHeaderCell;
                    if (objHeaderCell != null)
                    {
                        // Clear header filtering
                        objHeaderCell.FilterComboBox.SelectedIndex = -1;
                    }
                    else
                    {
                        // Clear filter cell filtering
                        DataGridViewColumn objDataGridViewColumn = objCustomFilterDialog.Column;
                        if (objDataGridViewColumn != null)
                        {
                            objDataGridViewColumn.ClearFilter(false);
                        }
                    }
                }
            }
        }
    }

